__bundle_register("games/phantom forces/render", function(require, _LOADED, __bundle_register, __bundle_modules)
local cache, memory, compatibility = require("games/phantom forces/cache"), require("modules/memory"), require("modules/compatibility")
local library, flags = cache.library, cache.library.flags

local fps, fps_count, fps_tick = 0, 0, compatibility.tick()
compatibility.render_connection(function()
    fps_count = fps_count + 1
    if compatibility.tick() - fps_tick >= 250 then
        fps = fps_count * 4
        fps_count = 0
        fps_tick = compatibility.tick()
    end
end)

compatibility.render_connection(function()
    if not memory.offsets then return end

    local tick = compatibility.tick()

    local screen_w = compatibility.get_screen_size(cache.instances.camera)
    local width = compatibility.get_text_size('Paragon - ' .. fps .. ' fps', 'SourceSansSemiBold')

    local x, y, w, h = screen_w - width - 24, 10, width + 14, 20
    compatibility.draw_rect_filled(x, y, w, h, library.theme.inline, 4, 255)
    compatibility.draw_rect_filled(x + 1, y + 1, w - 2, h - 2, library.theme.outline, 4, 255)

    compatibility.draw_text('Paragon', x + 7, y + 6, library.theme.element, 'SourceSansSemiBold')
    compatibility.draw_text(' - ' .. fps .. ' fps', x + 51, y + 6, library.theme.text_dark, 'SourceSansSemiBold')

    local sight, barrel, trigger = cache.local_player.weapon_sight, cache.local_player.weapon_barrel, cache.local_player.weapon_trigger

    local pj = sight and sight or barrel and barrel
    local cf = pj and memory.get_cframe(pj)

    local pjx, pjy = 0, 0
    if cf then
        local npjx, npjy, pjos = compatibility.world_to_screen(cf.Position + (cf.LookVector * 500))
        if pjos then
            pjx = math.floor(npjx)
            pjy = math.floor(npjy)
        else
            local mouse_pos = compatibility.get_mouse_location()
            pjx = mouse_pos[1]
            pjy = mouse_pos[2]
        end
    else
        local mouse_pos = compatibility.get_mouse_location()
        pjx = mouse_pos[1]
        pjy = mouse_pos[2]
    end

    if flags['scrosshair'] then
        local color = flags['scrosshair_color'].color

        compatibility.draw_line(pjx, pjy - 6, pjx, pjy + 7, Color3.fromRGB(0, 0, 0), 3)
        compatibility.draw_line(pjx - 6, pjy, pjx + 7, pjy, Color3.fromRGB(0, 0, 0), 3)

        compatibility.draw_line(pjx, pjy - 5, pjx, pjy + 6, color, 1)
        compatibility.draw_line(pjx - 5, pjy, pjx + 6, pjy, color, 1)
    end

    if flags['crosshair'] then
        local color = flags['crosshair_color']
        local outline_color = flags['crosshair_outline_color']

        if flags['crosshair_dot'] then
            compatibility.draw_circle(pjx, pjy, 1, outline_color.color, 3, 15, outline_color.alpha)
            compatibility.draw_circle(pjx, pjy, 1, color.color, 1, 15, color.alpha)
        end

        local step = 360 / flags['crosshair_lines']
        for i = 1, flags['crosshair_lines'] do
            local spin = flags['crosshair_spin_speed'] > 0 and tick / (11 - flags['crosshair_spin_speed']) or 0
            local angle = math.rad(spin + step * (i - 1))
            local direction = Vector3.new(math.cos(angle), math.sin(angle), 0)

            local t = tick * flags['crosshair_animation_speed'] * 0.001
            local alpha = (math.sin(t) + 1) * 0.5

            local gap = flags['crosshair_min_gap'] + (flags['crosshair_max_gap'] - flags['crosshair_min_gap']) * alpha
            local size = flags['crosshair_min_size'] + (flags['crosshair_max_size'] - flags['crosshair_min_size']) * alpha

            local in_from = Vector3.new(pjx, pjy, 0) + (direction * gap)
            local in_to = in_from + direction * size

            local out_from = (in_from - direction)
            local out_to = (in_to + direction)

            compatibility.draw_line(out_from.X, out_from.Y, out_to.X, out_to.Y, outline_color.color, 3, outline_color.alpha)
            compatibility.draw_line(in_from.X, in_from.Y, in_to.X, in_to.Y, color.color, 1, color.alpha)
        end
    end

    if flags['weapon_display'] then
        local trigger_pos = cache.instances.trigger_pos
        local weapon_name, weapon_ammo, weapon_max_ammo = cache.local_player.weapon_name, cache.local_player.weapon_ammo, cache.local_player.weapon_max_ammo

        if trigger_pos and weapon_name and weapon_ammo and weapon_max_ammo then
            local trx, try, tros = compatibility.world_to_screen(trigger_pos)
            if tros then
                trx = math.floor(trx)
                try = math.floor(try)

                weapon_name = string.lower(weapon_name)
                local width, height = compatibility.get_text_size(weapon_name .. ' - ' .. weapon_ammo .. '/' .. weapon_max_ammo, 'SourceSansSemiBold')

                local x, y, w, h = trx - width / 2, try - 16, width + 14, 32
                w = math.floor(w)

                compatibility.draw_rect_filled(x, y, w, h, library.theme.outline, 8, 255)
                compatibility.draw_rect_filled(x + 1, y + 1, w - 2, h - 2, library.theme.contrast_dark, 8, 255)

                compatibility.draw_text(weapon_name .. ' - ' .. weapon_ammo .. '/' .. weapon_max_ammo, x + 7, y + 7, library.theme.text, 'SourceSansSemiBold')

                local sx, sy, sw, sh = x + 7, y + 21, w - 14, 4
                compatibility.draw_rect_filled(sx, sy, sw, sh, library.theme.inline, 4, 255)
                compatibility.draw_rect_filled(sx + 1, sy + 1, sw - 2, sh - 2, library.theme.outline, 4, 255)

                local ssw = math.floor((weapon_ammo / weapon_max_ammo) * sw)
                if ssw > 0 then
                    compatibility.draw_rect_filled(sx, sy, ssw, sh, library.theme.accent, 4, 255)
                    compatibility.draw_rect_filled(sx + 1, sy + 1, ssw - 2, sh - 2, library.theme.element, 4, 255)
                end
            end
        end
    end

    if flags['grenades'] then
        for _, grenade in pairs(cache.grenades) do
            if grenade ~= 'nil' then
                if flags['grenades_trail'] then
                    local points = {}
                    for _, v in pairs(grenade.path) do
                        local x, y, os = compatibility.world_to_screen(v)
                        if os then
                            points[#points + 1] = { x, y }
                        end
                    end

                    local ctbl = flags['grenades_trail_color']
                    if #points >= 2 then
                        compatibility.draw_polyline(points, ctbl.color, false, 1, ctbl.alpha)
                    end
                end

                if grenade.distance < grenade.blastradius then
                    local damage = 0
                    if grenade.distance <= grenade.range0 then
                        damage = grenade.damage0
                    elseif grenade.distance <= grenade.range1 then
                        local t = (grenade.distance - grenade.range0) / (grenade.range1 - grenade.range0)
                        damage = math.floor(grenade.damage0 + (grenade.damage1 - grenade.damage0) * t)
                    else
                        damage = grenade.damage1
                    end

                    local gx, gy, gos = compatibility.world_to_screen(grenade.position)
                    if gos then
                        gx = math.floor(gx)
                        gx = math.floor(gx)

                        local grenade_name = string.lower(grenade.name)
                        local width, height = compatibility.get_text_size(grenade_name .. ' - ' .. damage .. ' dmg', 'SourceSansSemiBold')

                        local x, y, w, h = gx - width / 2, gy - 16, width + 14, 32
                        w = math.floor(w)

                        compatibility.draw_rect_filled(x, y, w, h, library.theme.outline, 8, 255)
                        compatibility.draw_rect_filled(x + 1, y + 1, w - 2, h - 2, library.theme.contrast_dark, 8, 255)

                        compatibility.draw_text(grenade_name .. ' - ' .. damage .. ' dmg', x + 7, y + 7, library.theme.text, 'SourceSansSemiBold')

                        local sx, sy, sw, sh = x + 7, y + 21, w - 14, 4
                        compatibility.draw_rect_filled(sx, sy, sw, sh, library.theme.inline, 4, 255)
                        compatibility.draw_rect_filled(sx + 1, sy + 1, sw - 2, sh - 2, library.theme.outline, 4, 255)

                        local ssw = math.floor(((tick - grenade.start) / grenade.fusetime) * sw)
                        if ssw > 0 then
                            compatibility.draw_rect_filled(sx, sy, ssw, sh, library.theme.accent, 4, 255)
                            compatibility.draw_rect_filled(sx + 1, sy + 1, ssw - 2, sh - 2, library.theme.element, 4, 255)
                        end
                    end
                end
            end
        end
    end

    if flags['players_steps'] then
        local color = flags['players_steps_color']

        for _, entry in pairs(cache.players) do
            if entry ~= 'nil' then
                for i, step in pairs(entry.step_points) do
                    local diff = tick - step.start
                    if diff > 1000 then
                        table.remove(entry.step_points, i)
                    else
                        local points = {}
                        for _, corner in pairs(step.corners) do
                            local x, y, os = compatibility.world_to_screen(corner)
                            if os then
                                points[#points+1] = {x, y}
                            end
                        end

                        if #points > 2 then
                            local convex = compatibility.draw_compute_convex(points)
                            if convex and #convex > 2 then
                                compatibility.draw_polyline(convex, color.color, true, 1, 128 - (diff / 1000) * 128)
                                compatibility.draw_convex_poly(convex, color.color, 64 - (diff / 1000) * 64)
                            end
                        end
                    end
                end
            end
        end
    end

    for i, hit in pairs(cache.hits) do
        if hit ~= 'nil' then
            local diff = tick - hit.start
            if diff >= 5000 then
                cache.hits[i] = 'nil'
            else
                if flags['players_hit_chams'] then
                    local fill = flags['players_hit_chams_fill']
                    local outline = flags['players_hit_chams_outline']
                    local lifetime = flags['players_hit_chams_lifetime'] * 1000

                    if diff < lifetime then
                        for _, part in pairs(hit.corners) do
                            local points = {}
                            for _, corner in pairs(part) do
                                local x, y, os = compatibility.world_to_screen(corner)
                                if os then
                                    points[#points+1] = {x, y}
                                end
                            end

                            if #points > 2 then
                                local convex = compatibility.draw_compute_convex(points)
                                if convex and #convex > 2 then
                                    compatibility.draw_polyline(convex, outline.color, true, 1, outline.alpha - (diff / lifetime) * outline.alpha)
                                    compatibility.draw_convex_poly(convex, fill.color, fill.alpha - (diff / lifetime) * fill.alpha)
                                end
                            end
                        end
                    end
                end

                if flags['players_hit_marker'] then
                    local color = flags['players_hit_marker_color']
                    local lifetime = flags['players_hit_marker_lifetime'] * 1000

                    if diff < lifetime then
                        local x, y, os = compatibility.world_to_screen(hit.position)
                        if os then
                            compatibility.draw_line(x - 5, y - 5, x + 5, y + 5, Color3.fromRGB(0, 0, 0), 3, 255 - (diff / lifetime) * 255)
                            compatibility.draw_line(x + 5, y - 5, x - 5, y + 5, Color3.fromRGB(0, 0, 0), 3, 255 - (diff / lifetime) * 255)

                            compatibility.draw_line(x - 5, y - 5, x + 5, y + 5, color.color, 1, 255 - (diff / lifetime) * 255)
                            compatibility.draw_line(x + 5, y - 5, x - 5, y + 5, color.color, 1, 255 - (diff / lifetime) * 255)
                        end
                    end
                end
            end
        end
    end

    if flags['players_kdr'] or flags['players_rank'] then
        local kdr_color = flags['players_kdr_color']
        local rank_color = flags['players_rank_color']

        for _, entry in pairs(compatibility.get_entity_list(true)) do
            local leaderboard = cache.leaderboard[entry.name]
            if leaderboard then
                local bbox = entry.bounding_box
                if bbox and bbox.x > 0 and bbox.y > 0 then
                    local offset = -3

                    if flags['players_rank'] then
                        compatibility.draw_text('LVL: ' .. leaderboard.rank, bbox.x + bbox.w + 3, bbox.y + offset, rank_color.color, 'SmallestPixel', rank_color.alpha)
                        offset = offset + 8
                    end

                    if flags['players_kdr'] then
                        compatibility.draw_text('KDR: ' .. leaderboard.kdr, bbox.x + bbox.w + 3, bbox.y + offset, kdr_color.color, 'SmallestPixel', kdr_color.alpha)
                        offset = offset + 8
                    end
                end
            end
        end
    end
end)
end)
__bundle_register("modules/compatibility", function(require, _LOADED, __bundle_register, __bundle_modules)
local compatibility = {}

local builtin_font = font
local font, crypt = require("modules/font"), require("modules/crypt")

if cheat then
    compatibility.context = 'Serotonin'
    compatibility.rbx_version = package.cpath:match('version%-[%w]+')

    if not compatibility.rbx_version then
        compatibility.no_version = true
        compatibility.rbx_version = 'version-90f2fddd3b244ff6'
    end

    --? game functions
    compatibility.tick = utility.get_tick_count

    compatibility.get_camera_pos = function(c)
        return game.CameraPosition
    end

    local ws = game.Workspace
    compatibility.get_children = ws.GetChildren
    compatibility.get_descendants = ws.GetDescendants
    compatibility.find_first_child = ws.FindFirstChild
    compatibility.find_first_child_of_class = ws.FindFirstChildOfClass

    compatibility.get_datamodel = function() return game.Datamodel end
    compatibility.get_local_player = function() return game.LocalPlayer end

    compatibility.get_attributes = function(i)
        local f = {}

        for _, att in pairs(i:GetAttributes()) do
            f[att.Name] = att.Value
        end

        return f
    end

    --? file functions
    compatibility.list_files = function(path)
        local d = {}
        for i, f in pairs(file.listdir(path)) do
            d[i] = f.name
        end
        return d
    end

    compatibility.read_file = file.read
    compatibility.write_file = file.write
    compatibility.delete_file = file.delete

    --? ipnut functions
    compatibility.key_press = keyboard.press
    compatibility.key_release = keyboard.release
    compatibility.mouse_press = mouse.press
    compatibility.mouse_release = mouse.release
    compatibility.mouse_scroll = mouse.scroll
    compatibility.is_key_pressed = keyboard.is_pressed
    compatibility.get_mouse_location = utility.get_mouse_pos
    compatibility.move_mouse_relative = utility.move_mouse

    --? connect functions
    compatibility.slow_connection = function(callback)
        cheat.register('onSlowUpdate', callback)
    end

    compatibility.update_connection = function(callback)
        cheat.register('onUpdate', callback)
    end

    compatibility.render_connection = function(callback)
        cheat.register('onPaint', callback)
    end

    --? drawing functions
    local ddt, fdt, dgt, fgt = draw.text_outlined, font.draw_text, draw.get_text_size, font.get_text_size

    compatibility.draw_text = function(text, x, y, color, font_name, alpha)
        if font_name == 'SmallestPixel' then
            ddt(text, x, y, color, font_name, alpha)
        else
            fdt(text, x, y, color, font_name, alpha)
        end
    end

    compatibility.get_text_size = function(text, font_name)
        if font_name == 'SmallestPixel' then
            return dgt(text, font_name)
        else
            return fgt(text, font_name)
        end
    end

    compatibility.queued_get_text_size = compatibility.get_text_size

    local wts = utility.world_to_screen
    compatibility.world_to_screen = wts

    compatibility.mass_project = function(points)
        local n = {}
        for _, p in pairs(points) do
            local x, y, os = wts(p)
            if os then
                n[#n+1] = {x, y}
            end
        end

        return n
    end

    compatibility.load_image = utility.load_image
    compatibility.draw_circle = draw.circle
    compatibility.draw_circle_filled = draw.circle_filled
    compatibility.draw_line = draw.line
    compatibility.draw_rect = draw.rect
    compatibility.draw_rect_filled = draw.rect_filled
    compatibility.draw_gradient = draw.gradient
    compatibility.draw_image = draw.image
    compatibility.draw_polyline = draw.polyline
    compatibility.draw_convex_poly = draw.convex_poly_filled
    compatibility.draw_compute_convex = draw.compute_convex_hull

    local mp, dcc, dcp, dpl = compatibility.mass_project, compatibility.draw_compute_convex, compatibility.draw_convex_poly, compatibility.draw_polyline
    compatibility.highlight_from_corners = function(corners, out_color, out_alpha, in_color, in_alpha)
        local projected = mp(corners)

        if #projected >= 2 then
            local convex = dcc(projected)
            if convex and #convex >= 2 then
                dcp(convex, in_color, in_alpha)
                dpl(convex, out_color, true, 1, out_alpha)
            end
        end
    end

    --? memory functions
    local r, w = memory.read, memory.write

    local types = {
