local floor, sub = math.floor, string.sub
font.draw_text = function(text, x, y, color, font_name, alpha)
    font_name = font_name or 'Interum'
    alpha = alpha or 255

    local font_data = characters[font_name]
    local font_textures = textures[font_name]

    local xpos, ypos = floor(x), floor(y)

    for i = 1, #text do
        local character = sub(text, i, i)
        local char_data = font_data[character]
        if character == ' ' then
            xpos = xpos + font_data[' '].width
        elseif char_data then
            draw_image(font_textures[character], xpos, ypos + char_data.offset, char_data.width, char_data.height, color, alpha)
            xpos = xpos + char_data.width + font_data.gap
        end
    end
end

font.get_text_size = function(text, font_name)
    font_name = font_name or 'Interum'

    local font_data = characters[font_name]
    local x, y = 0, 0

    for i = 1, #text do
        local character = sub(text, i, i)
        local char_data = font_data[character]

        if character == ' ' then
            x = x + font_data[' '].width
        elseif char_data then
            x = x + char_data.width

            if i ~= #text then
                x = x + font_data.gap
            end

            if char_data.height > y then
                y = char_data.height
            end
        end
    end

    return x, y
end

return font
