local read_float, read_double, read_int, read_uint, read_short, read_ushort, read_byte, read_bool, read_int64, read_uint64, read_pointer, read_string = compatibility.read_float, compatibility.read_double, compatibility.read_int, compatibility.read_uint, compatibility.read_short, compatibility.read_ushort, compatibility.read_byte, compatibility.read_bool, compatibility.read_int64, compatibility.read_uint64, compatibility.read_pointer, compatibility.read_string
local write_float, write_double, write_int, write_uint, write_short, write_ushort, write_byte, write_bool, write_int64, write_uint64, write_pointer, write_string = compatibility.write_float, compatibility.write_double, compatibility.write_int, compatibility.write_uint, compatibility.write_short, compatibility.write_ushort, compatibility.write_byte, compatibility.write_bool, compatibility.write_int64, compatibility.write_uint64, compatibility.write_pointer, compatibility.write_string

local color3, color3_rgb, vector3 = Color3.new, Color3.fromRGB, Vector3.new
module.read = function(address, class, property)
    local class_data = module.offsets[class] and module.offsets[class][property]
    if class_data then
        local offset = class_data[1]
        local memory_type = class_data[2]
        local memory_vector = class_data[3]

        if memory_vector then
            local func = compatibility['read_' .. memory_type]

            local first = func(address + offset)
            local second = func(address + offset + 4)

            local third = 0
            if memory_vector ~= 'Vector2' then
                third = func(address + offset + 8)
            end

            if memory_vector == 'Color3_RGB' then
                return color3_rgb(first, second, third)
            end

            if memory_vector == 'Color3' then
                return color3(first, second, third)
            end

            return vector3(first, second, third)
        else
            return compatibility['read_' .. memory_type](address + offset)
        end
    end
end

module.write = function(address, class, property, value)
    local class_data = module.offsets[class] and module.offsets[class][property]
    if class_data then
        local offset = class_data[1]
        local memory_type = class_data[2]
        local memory_vector = class_data[3]

        if memory_vector then
            local func = compatibility['write_' .. memory_type]

            if memory_vector == 'Vector3' then
                func(address + offset, value.X)
                func(address + offset + 4, value.Y)
                func(address + offset + 8, value.Z)
            elseif memory_vector == 'Color3' then
                func(address + offset, value.R)
                func(address + offset + 4, value.G)
                func(address + offset + 8, value.B)
            elseif memory_vector == 'Color3_RGB' then
                func(address + offset, value.R)
                func(address + offset + 1, value.G)
                func(address + offset + 2, value.B)
            elseif memory_vector == 'Vector2' then
                func(address + offset, value.X)
                func(address + offset + 4, value.Y)
            end
        else
            return compatibility['write_' .. memory_type](address + offset, value)
        end
    end
end

module.write_vector3 = function(base, x, y, z)
    write_float(base, x)
    write_float(base + 4, y)
    write_float(base + 8, z)
end

module.get_attachment_position = function(attachment, parent)
    if parent then
        local parentpos = parent.Position
        local transform = module.read(attachment.Address, 'Attachment', 'TransformPosition')
        return parentpos + transform
    else
        local transform = module.read(attachment.Address, 'Attachment', 'TransformPosition')
        return transform
    end
end

module.get_attachment_transform = function(attachment, only_look)
    local base = attachment.Address + module.offsets.Attachment.Transform[1]

    if only_look then
        local r02 = read_float(base + 8)
        local r12 = read_float(base + 20)
        local r22 = read_float(base + 32)
        return vector3(-r02, -r12, -r22)
    else
        local r00 = read_float(base)
        local r01 = read_float(base + 4)
        local r02 = read_float(base + 8)

        local r10 = read_float(base + 12)
        local r11 = read_float(base + 16)
        local r12 = read_float(base + 20)

        local r20 = read_float(base + 24)
        local r21 = read_float(base + 28)
        local r22 = read_float(base + 32)

        local x = read_float(base + 36)
        local y = read_float(base + 40)
        local z = read_float(base + 44)

        return {
            Position = vector3(x, y, z),
            LookVector = vector3(-r02, -r12, -r22),
            RightVector = vector3(r00, r10, r20),
            UpVector = vector3(r01, r11, r21)
        }
    end
end

module.get_cframe = function(part)
    if compatibility.context == 'Serotonin' then
        return {
            Position = part.Position,
            LookVector = part.LookVector,
            RightVector = part.RightVector,
            UpVector = part.UpVector
        }
    elseif compatibility.context == 'RbxCli' then
        local cf = part.CFrame
        if cf then
            return {
                Position = cf.Position,
                LookVector = cf.LookVector,
                RightVector = cf.RightVector,
                UpVector = cf.UpVector
            }
        else
            return {
                Position = vector3(0, 0, 0),
                LookVector = vector3(0, 0, 0),
                RightVector = vector3(0, 0, 0),
                UpVector = vector3(0, 0, 0)
            }
        end
    end
end

module.get_components = function(cframe, offset)
    local base = cframe + offset

    local r00 = read_float(base)
    local r01 = read_float(base + 4)
    local r02 = read_float(base + 8)

    local r10 = read_float(base + 12)
    local r11 = read_float(base + 16)
    local r12 = read_float(base + 20)

    local r20 = read_float(base + 24)
    local r21 = read_float(base + 28)
    local r22 = read_float(base + 32)

    local x = read_float(base + 36)
    local y = read_float(base + 40)
    local z = read_float(base + 44)

    return {
        r00, r01, r02,
        r10, r11, r12,
        r20, r21, r22,
        x, y, z
    }
end

module.write_components = function(cframe, offset, components)
    local base = cframe + offset

    write_float(base, components[1])
    write_float(base + 4, components[2])
    write_float(base + 8, components[3])

    write_float(base + 12, components[4])
    write_float(base + 16, components[5])
    write_float(base + 20, components[6])

    write_float(base + 24, components[7])
    write_float(base + 28, components[8])
    write_float(base + 32, components[9])

    write_float(base + 36, components[10])
    write_float(base + 40, components[11])
    write_float(base + 44, components[12])
end

module.transform_components = function(a, b)
    return {
        a[1] * b[1] + a[2] * b[4] + a[3] * b[7],
        a[1] * b[2] + a[2] * b[5] + a[3] * b[8],
        a[1] * b[3] + a[2] * b[6] + a[3] * b[9],

        a[4] * b[1] + a[5] * b[4] + a[6] * b[7],
        a[4] * b[2] + a[5] * b[5] + a[6] * b[8],
        a[4] * b[3] + a[5] * b[6] + a[6] * b[9],

        a[7] * b[1] + a[8] * b[4] + a[9] * b[7],
        a[7] * b[2] + a[8] * b[5] + a[9] * b[8],
        a[7] * b[3] + a[8] * b[6] + a[9] * b[9],

        a[1] * b[10] + a[2] * b[11] + a[3] * b[12] + a[10],
        a[4] * b[10] + a[5] * b[11] + a[6] * b[12] + a[11],
        a[7] * b[10] + a[8] * b[11] + a[9] * b[12] + a[12],
    }
end

module.get_camera_cframe = function(camera)
    local address = camera.Address
    local cframe = module.offsets['Camera']['CFrame'][1]

    local base = address + cframe

    local r00 = read_float(base)
    local r01 = read_float(base + 4)
    local r02 = read_float(base + 8)

    local r10 = read_float(base + 12)
    local r11 = read_float(base + 16)
    local r12 = read_float(base + 20)

    local r20 = read_float(base + 24)
    local r21 = read_float(base + 28)
    local r22 = read_float(base + 32)

    local x = read_float(base + 36)
    local y = read_float(base + 40)
    local z = read_float(base + 44)

    return {
        Position = vector3(x, y, z),
        LookVector = vector3(-r02, -r12, -r22),
        RightVector = vector3(r00, r10, r20),
        UpVector = vector3(r01, r11, r21),
    }
end

module.offset_cframe = function(cframe, position)
    local pos, look, right, up = cframe.Position, cframe.LookVector, cframe.RightVector, cframe.UpVector
    return pos + right * position.X + up * position.Y + look * position.Z
end

module.get_bone_cframe = function(bone, offset)
    local base = bone + offset

    local r00 = read_float(base)
    local r10 = read_float(base + 4)
    local r20 = read_float(base + 8)

    local x = read_float(base + 12)
    local y = read_float(base + 16)
    local z = read_float(base + 20)

    local r01 = read_float(base + 24)
    local r11 = read_float(base + 28)
    local r21 = read_float(base + 32)

    local r02 = r10 * r21 - r20 * r11
    local r12 = r20 * r01 - r00 * r21
    local r22 = r00 * r11 - r10 * r01

    return {
        r00, r01, r02,
        r10, r11, r12,
        r20, r21, r22,
        x, y, z
    }
end

module.get_transformed_bone = function(bone)
    local function get_cframe(obj)
        local class = obj.ClassName
        if class ~= 'Bone' and class ~= 'Part' and class ~= 'MeshPart' then
            return nil
        end

        if class ~= 'Bone' then
            local prim = read_pointer(obj.Address + module.offsets['BasePart']['Primitive'][1])
            return module.get_components(prim, module.offsets['BasePart']['CFrame'][1])
        end

        local parent_cframe = get_cframe(obj.Parent)
        if not parent_cframe then return nil end

        local bone_cframe = module.get_bone_cframe(obj.Address, module.offsets['Bone']['CFrame'][1])
        local bone_transform = module.get_components(obj.Address, module.offsets['Bone']['Transform'][1])

        local bone_world_transformed = module.transform_cframe(parent_cframe, bone_cframe)
        return module.transform_cframe(bone_world_transformed, bone_transform)
    end

    return get_cframe(bone)
end

module.get_color_sequence = function(address, array_offset)
    local array = read_pointer(address + array_offset)
    local count = read_int(address + array_offset + 8)

    local keypoints = {}
    for i = 0, count - 1 do
        local base = array + (i * 20)
        keypoints[#keypoints+1] = {
            time = read_float(base),
            color = color3(read_float(base + 4), read_float(base + 8), read_float(base + 12)),
            envelope = read_float(base + 16)
        }
    end

    return keypoints
end

module.write_color_sequence = function(address, array_offset, value)
    local array = read_pointer(address + array_offset)
    local count = read_int(address + array_offset + 8)

    local replace = {}
    for _, seq in pairs(value) do
        local color = seq.color
        replace[seq.time] = {
            r = color.R,
            g = color.G,
            b = color.B,
            envelope = seq.envelope
        }
    end

    for i = 0, count - 1 do
        local base = array + (i * 20)

        local replacement = replace[read_float(base)]
        if replacement then
            write_float(base + 4, replacement.r)
            write_float(base + 8, replacement.g)
            write_float(base + 12, replacement.b)
            write_float(base + 16, replacement.envelope)
        end
    end
end

module.get_number_sequence = function(address, array_offset)
    local array = read_pointer(address + array_offset)
    local count = read_int(address + array_offset + 8)

    local keypoints = {}
    for i = 0, count - 1 do
        local base = array + (i * 12)
        keypoints[#keypoints+1] = {
            time = read_float(base),
            value = read_float(base + 4),
            envelope = read_float(base + 8)
        }
    end

    return keypoints
end

module.get_corners = function(cframe, size)
    local pos, look, right, up = cframe.Position, cframe.LookVector, cframe.RightVector, cframe.UpVector

    local half = size / 2
    local hx, hy, hz = half.X, half.Y, half.Z

    local corners = {
        pos + up * hy + look * hz + right * hx,
        pos + up * hy + look * hz - right * hx,
        pos + up * hy - look * hz + right * hx,
        pos + up * hy - look * hz - right * hx,
        pos - up * hy + look * hz + right * hx,
        pos - up * hy + look * hz - right * hx,
        pos - up * hy - look * hz + right * hx,
        pos - up * hy - look * hz - right * hx,
    }

    return corners
end

module.get_half_corners = function(cframe, size)
    local pos = cframe.Position
    local right = cframe.RightVector
    local up = cframe.UpVector
    local look = cframe.LookVector

    local half = size * 0.5
    local hy = half.Y

    local r = right * half.X
    local l = look * half.Z

    return {
        pos + r + l + up * hy,
        pos - r + l + up * hy,
        pos - r - l + up * hy,
        pos + r - l + up * hy
    }
end

module.draw_corners = function(corners, color, alpha, fill_alpha)
    local screen_points = {}

    for _, corner in pairs(corners) do
        local x, y, os = compatibility.world_to_screen(corner)
        if os then
            screen_points[#screen_points+1] = {x, y}
        end
    end

    if #screen_points > 3 then
        local convex = compatibility.draw_compute_convex(screen_points)
        if convex and #convex > 3 then
            compatibility.draw_convex_poly(convex, color, fill_alpha or alpha)
            compatibility.draw_polyline(convex, color, true, 1, alpha)
        end
    end
end

module.get_animation_tracks = function(animator)
    local tracks = {}

    local track_list = read_pointer(animator.Address + module.offsets['Animator']['TrackList'][1])
    if track_list == 0 then return end

    local start = read_pointer(track_list)
    while start ~= 0 and start ~= track_list do
        local track = read_pointer(start + 0x10)
        if track ~= 0 then
            local animation = read_pointer(track + module.offsets['AnimationTrack']['Animation'][1])
            if animation ~= 0 then
                local animation_id = read_string(animation + module.offsets['Animation']['AnimationId'][1])
                if animation_id ~= '' then
                    tracks[#tracks + 1] = {
                        track = track,
                        animation_id = animation_id
                    }
                end
            end
        end

        start = read_pointer(start)
    end

    return tracks
end

module.read_animation_track = function(track)
    return {
        AnimationId = track.animation_id,
        Speed = read_float(track.track + module.offsets['AnimationTrack']['Speed'][1]),
        WeightTarget = read_float(track.track + module.offsets['AnimationTrack']['WeightTarget'][1]),
        TimePosition = read_float(track.track + module.offsets['AnimationTrack']['TimePosition'][1])
    }
end

return module
end)
