    [0x53] = 'S',
    [0x54] = 'T',
    [0x55] = 'U',
    [0x56] = 'V',
    [0x57] = 'W',
    [0x58] = 'X',
    [0x59] = 'Y',
    [0x5A] = 'Z',

    [0x70] = 'F1',
    [0x71] = 'F2',
    [0x72] = 'F3',
    [0x73] = 'F4',
    [0x74] = 'F5',
    [0x75] = 'F6',
    [0x76] = 'F7',
    [0x77] = 'F8',
    [0x78] = 'F9',
    [0x79] = 'F10',
    [0x7A] = 'F11',
    [0x7B] = 'F12',

    [0xA0] = 'LShift',
    [0xA1] = 'RShift',
    [0xA2] = 'LCtrl',
    [0xA3] = 'RCtrl',
    [0xA4] = 'LAlt',
    [0xA5] = 'RAlt',
    [0x20] = 'Space',

    [0x23] = 'End',
    [0x24] = 'Home',
    [0x2D] = 'Insert',
    [0x2E] = 'Delete'
}

local UDim2 = {}; do
    UDim2.new = function(xScale, xOffset, yScale, yOffset)
        return {
            X = xOffset,
            Y = yOffset,
            Width = xScale,
            Height = yScale
        }
    end
end

local Vector2 = {}; do
    Vector2.__index = Vector2

    function Vector2.new(x, y)
        local self = setmetatable({}, Vector2)
        self.X = x or 0
        self.Y = y or 0
        return self
    end

    Vector2.__add = function(a, b)
        return Vector2.new(a.X + b.X, a.Y + b.Y)
    end

    Vector2.__sub = function(a, b)
        return Vector2.new(a.X - b.X, a.Y - b.Y)
    end

    Vector2.__mul = function(a, b)
        if type(a) == 'number' then
            return Vector2.new(a * b.X, a * b.Y)
        elseif type(b) == 'number' then
            return Vector2.new(b * a.X, b * a.Y)
        end
    end

    Vector2.__tostring = function(v)
        return string.format('(%s, %s)', v.X, v.Y)
    end
end

local Instance = {}; do
    Instance.new = function(class, settings)
        local properties = {
            index = settings.zindex or #library.objects + 1,

            class = class,

            parent = settings.parent,
            children = {},

            inputs = {active = {}, connections = {}},
            tweens = {},
            mouse_over = false,

            size = UDim2.new(0, 0, 0, 0),
            position = UDim2.new(0, 0, 0, 0),
            alpha = 255,

            absolute_size = Vector2.new(0, 0),
            absolute_position = Vector2.new(0, 0)
        }

        properties.Tween = function(self, property, value, duration)
            local tick = compatibility.tick()
            local from = self[property]

            table.insert(self.tweens, {
                index = #self.tweens + 1,
                start = tick,
                from = from,
                to = value,
                property = property,
                duration = duration
            })
        end

        properties.Destroy = function(self)
            local function clear(object)
                for _, child in pairs(object:GetChildren()) do
                    clear(child)
                end

                local parent = object.parent
                if parent and parent.children then
                    for i, child in pairs(parent:GetChildren()) do
                        if child.index == object.index then
                            parent.children[i] = nil
                            break
                        end
                    end
                end

                library.directs[object.index] = nil
                library.objects[object.index] = nil
            end

            clear(self)
        end

        properties.GetChildren = function(self)
            return self.children
        end

        properties.GetDescendants = function(self)
            local descendants = {}

            local function search(object)
                for _, child in pairs(object:GetChildren()) do
                    descendants[#descendants+1] = child
                    search(child)
                end
            end

            search(self)

            return descendants
        end

        properties.Refresh = function(self)
            for _, descendant in pairs(self:GetDescendants()) do
                local size, position = descendant.size, descendant.position

                local parent = descendant.parent
                if parent then
                    local absolute_size, absolute_position = parent.absolute_size, parent.absolute_position

                    descendant.absolute_size = Vector2.new(
                        math.floor(absolute_size.X * size.Width + size.X),
                        math.floor(absolute_size.Y * size.Height + size.Y)
                    )

                    descendant.absolute_position = Vector2.new(
                        math.floor(absolute_position.X + absolute_size.X * position.Width + position.X),
                        math.floor(absolute_position.Y + absolute_size.Y * position.Height + position.Y)
                    )
                end
            end
        end

        local metatable = setmetatable({}, {
            __index = function(self, key)
                if key == 'register' then
                    return function(keycode, mode, callback)
                        table.insert(properties.inputs.connections, {keycode = keycode, mode = mode, callback = callback})
                    end
                else
                    return properties[key]
                end
            end,

            __newindex = function(self, key, value)
                if key == 'size' then
                    local parent = properties.parent
                    if parent then
                        properties.size = value

                        local parent_size = parent.absolute_size
                        properties.absolute_size = Vector2.new(
                            math.floor(parent_size.X * value.Width + value.X),
                            math.floor(parent_size.Y * value.Height + value.Y)
                        )

                        properties:Refresh()
                    else
                        properties.size = value
                        properties.absolute_size = Vector2.new(value.X, value.Y)

                        properties:Refresh()
                    end
                elseif key == 'position' then
                    local parent = properties.parent
                    if parent then
                        properties.position = value

                        local parent_size, parent_position = parent.absolute_size, parent.absolute_position
                        properties.absolute_position = Vector2.new(
                            math.floor(parent_position.X + parent_size.X * value.Width + value.X),
                            math.floor(parent_position.Y + parent_size.Y * value.Height + value.Y)
                        )

                        properties:Refresh()
                    else
                        properties.position = value
                        properties.absolute_position = Vector2.new(value.X, value.Y)
                        properties:Refresh()
                    end
                elseif key == 'visible' then
                    properties.visible = value

                    local check = function(object)
                        while object do
                            if not object.visible then
                                return false
                            end

                            object = object.parent
                        end

                        return true
                    end

                    local active = check(properties)
                    properties.active = active

                    for _, descendant in pairs(properties:GetDescendants()) do
                        local active = check(descendant)
                        if descendant.visible and active then
                            descendant.active = descendant.was_active or true
                        else
                            descendant.was_active = descendant.active
                            descendant.active = false
                        end
                    end
                else
                    properties[key] = value
                end
            end
        })

        metatable.visible = true
        for i, v in pairs(settings) do
            metatable[i] = v
        end

        if properties.parent then
            table.insert(properties.parent.children, metatable)
        end

        library.objects[properties.index] = metatable
        library.directs[properties.index] = properties
        return metatable
    end
end

local notifications = {active = {}}; do
    local holder = Instance.new('frame', {
        size = UDim2.new(0, 0, 0, 0),
        position = UDim2.new(0, 10, 0, 66),
        color = Color3.new(0, 0, 0),
        alpha = 0,
        zindex = 1000,
        always = true
    })
    notifications.holder = holder

    local update_list = function()
        local offset = 0

        for _, notification in pairs(notifications.active) do
            local holder = notification.holder

            if holder then
                if holder.tweens and #holder.tweens ~= 0 then
                    for _, tween in pairs(holder.tweens) do
                        tween.from = UDim2.new(0, -100, 0, offset)
                        tween.to = UDim2.new(0, 0, 0, offset)
                    end
                else
                    holder.position = UDim2.new(0, 0, 0, offset)
                end

                offset = offset + holder.absolute_size.Y + 10
            end
        end
    end

    notifications.clear = function()
        for _, notification in pairs(notifications.active) do
            notification.holder:Destroy()
        end
        notifications.active = {}
    end

    compatibility.update_connection(function()
        local tick = compatibility.tick()

        for i = #notifications.active, 1, -1 do
            local notification = notifications.active[i]
            local diff = tick - notification.start

            if diff >= notification.duration - library.tween_duration then
                notification.holder:Tween('position', UDim2.new(0, -100, 0, notification.holder.position.Y), library.tween_duration)
            end

            if diff >= notification.duration then
                notification.holder:Destroy()
                table.remove(notifications.active, i)
                update_list()
            end
        end
    end)
end
library.notifications = notifications

library.save = function()
    local encoded = {}

    for flag, element in pairs(library.elements) do
        local v = library.flags[flag]
        if element.type == 'colorpicker' then
            encoded[flag] = {color = v.color:ToHex(), alpha = v.alpha}
        elseif element.type == 'keypicker' then
            encoded[flag] = {key = element.value.key, mode = element.value.mode}
        else
            encoded[flag] = v
        end
    end

    return crypt.json.encode(encoded)
end

library.load = function(encoded)
    if type(encoded) == 'buffer' and buffer and buffer.tostring then
        encoded = buffer.tostring(encoded)
    end

    local decoded = crypt.json.decode(encoded)

    for flag, v in pairs(decoded) do
        local element = library.elements[flag]
        if element then
            if element.type == 'colorpicker' then
                element.set({color = Color3.fromHex(v.color), alpha = v.alpha})
            elseif element.type == 'keypicker' then
                element.set({key = v.key and tonumber(v.key) or nil, mode = v.mode})
            else
                element.set(v)
            end
        end
    end
end

library.notify = function(self, config)
    local config = {
        type = config.type or 'info',
        title = config.title or 'Title',
        description = config.description or 'Description',
        duration = config.duration or 7
    }

    local notification = {duration = config.duration * 1000, start = compatibility.tick()}

    local offset = 0
    for _, child in pairs(notifications.holder:GetChildren()) do
        offset = offset + child.absolute_size.Y + 10
    end

    local w = compatibility.queued_get_text_size(#config.description > #config.title and config.description or config.title, library.font)
    local holder = Instance.new('frame', {
        size = UDim2.new(0, w + 14, 0, 36),
        position = UDim2.new(0, -100, 0, offset),
        color = library.theme.inline,
        parent = notifications.holder,
        rounding = 4,
        always = true
    })
    holder:Tween('position', UDim2.new(0, 0, 0, offset), library.tween_duration)

    notification.holder = holder
    table.insert(notifications.active, notification)

    local inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        parent = holder,
        rounding = 4,
        always = true
    })

    Instance.new('image', {
        size = UDim2.new(0, 12, 0, 12),
        position = UDim2.new(0, 5, 0, 4),
        color = config.type == 'info' and Color3.fromRGB(255, 255, 255) or Color3.fromRGB(255, 0, 0),
        texture = config.type == 'info' and assets.info or assets.error,
        parent = inner,
        always = true
    })

    local title = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 22, 0, 6),
        color = library.theme.text_dark,
        parent = inner,
        always = true
    })

    local description = Instance.new('text', {
        text = config.description,
        position = UDim2.new(0, 6, 0, 20),
        color = library.theme.text,
        parent = inner,
        always = true
    })

    notification.remove = function()
        notification.duration = library.tween_duration
    end

    notification.set_description = function(value)
        description.text = value
        local w = compatibility.queued_get_text_size(#value > #config.title and value or config.title, library.font)
        holder.size = UDim2.new(0, w + 14, 0, 36)
    end

    return notification
end

library.mouse_over = function(mouse_pos, object)
    local mpx, mpy = mouse_pos[1], mouse_pos[2]
    local size, position = object.absolute_size, object.absolute_position
    return mpx >= position.X and mpx <= position.X + size.X and mpy >= position.Y and mpy <= position.Y + size.Y
end

library.window = function(self, config)
    local config = {
        title = config.title or 'Window',
        sub_title = config.sub_title or nil,
        size = config.size or UDim2.new(0, 550, 0, 400)
    }

    local window = {
        pages = {}
    }

    local outer = Instance.new('frame', {
        size = config.size,
        position = UDim2.new(0, (screen_w / 2) - (config.size.X / 2), 0, (screen_h / 2) - (config.size.Y / 2)),
        color = library.theme.outline,
        rounding = 8
    })

    local dragging = false
    outer.register(0x01, 'began', function() dragging = true end)
    outer.register(0x01, 'ended', function() dragging = false end)

    local last_mouse_pos = compatibility.get_mouse_location()
    compatibility.update_connection(function()
        local mouse_pos = compatibility.get_mouse_location()

        if dragging then
            local dx, dy = mouse_pos[1] - last_mouse_pos[1], mouse_pos[2] - last_mouse_pos[2]
            outer.position = UDim2.new(0, outer.absolute_position.X + dx, 0, outer.absolute_position.Y + dy)
        end

        last_mouse_pos = mouse_pos
    end)

    local a = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.contrast_dark,
        rounding = 8,
        parent = outer
    })

    local title_w = compatibility.queued_get_text_size(config.title, library.font)
    local sub_title_w = config.sub_title and compatibility.queued_get_text_size(config.sub_title, library.font) + 12 or 0

    local b = Instance.new('frame', {
        size = UDim2.new(0, title_w + sub_title_w + 17, 0, 30),
        position = UDim2.new(0, 10, 0, 10),
        color = library.theme.accent,
        rounding = 4,
        parent = a
    })

    Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.accent_dark,
        rounding = 4,
        parent = b
    })

    Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 7, 0, 11),
        color = library.theme.text,
        parent = b
    })

    if config.sub_title then
        Instance.new('frame', {
            size = UDim2.new(0, 1, 0, 14),
            position = UDim2.new(0, title_w + 15, 0, 8),
            color = library.theme.accent,
            parent = b
        })

        Instance.new('text', {
            text = config.sub_title,
            position = UDim2.new(0, title_w + 22, 0, 11),
            color = library.theme.text_dark,
            parent = b
        })
    end

    Instance.new('frame', {
        size = UDim2.new(1, -20, 0, 1),
        position = UDim2.new(0, 10, 0, 50),
        color = library.theme.outline,
        parent = a
    })

    local tabs_outer = Instance.new('frame', {
        size = UDim2.new(0, 200, 0, 30),
        position = UDim2.new(1, -210, 0, 10),
        color = library.theme.inline,
        rounding = 4,
        parent = a
    })

    local tabs_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.contrast,
        rounding = 4,
        parent = tabs_outer
    })

    local tabs_select = Instance.new('frame', {
        size = UDim2.new(0, 50, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.accent,
        rounding = 4,
        parent = tabs_inner
    })

    local tabs_select_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.accent_dark,
        rounding = 4,
        parent = tabs_select
    })

    local tabs_pages = Instance.new('frame', {
        size = UDim2.new(1, -20, 1, -61),
        position = UDim2.new(0, 10, 0, 61),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = a
    })

    window.tabs_outer = tabs_outer
    window.tabs_inner = tabs_inner
    window.tabs_select = tabs_select
    window.tabs_pages = tabs_pages

    return setmetatable(window, {__index = library})
end

library.page = function(self, config)
    local config = {
        title = config.title or 'Page',
        texture = config.texture or nil
    }

    local width = compatibility.queued_get_text_size(config.title, library.font) + 12
    if config.texture then
        width = width + 18
    end

    local page = {
        title = config.title,
        width = width,
        sections = {}
    }

    local index = #self.pages + 1
    page.index = index
    self.pages[index] = page

    local tabs_size, tab_offset = 0, 0
    for _, a_page in pairs(self.pages) do
        local current_tab_width = a_page.width

        if a_page ~= page then
            tab_offset = tab_offset + current_tab_width
        end
        tabs_size = tabs_size + current_tab_width
    end

    self.tabs_outer.size = UDim2.new(0, tabs_size + 3, 0, 30)
    self.tabs_outer.position = UDim2.new(1, -tabs_size - 13, 0, 10)

    local tab = Instance.new('frame', {
        size = UDim2.new(0, page.width, 1, 0),
        position = UDim2.new(0, tab_offset, 0, 0),
        color = Color3.fromRGB(0, 0, 0),
        alpha = 0,
        parent = self.tabs_inner
    })

    if config.texture then
        local tab_image = Instance.new('image', {
            size = UDim2.new(0, 12, 0, 12),
            position = UDim2.new(0, 6, 0, 9),
            texture = config.texture,
            color = library.theme.text_darker,
            parent = tab
        })
        page.tab_image = tab_image
    end

    local tab_text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 24, 0, 11),
        color = library.theme.text_darker,
        parent = tab
    })
    page.tab_text = tab_text

    local actual_page = Instance.new('frame', {
        size = UDim2.new(1, 0, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        visible = false,
        parent = self.tabs_pages
    })
    page.actual_page = actual_page

    local left_page = Instance.new('frame', {
        size = UDim2.new(0.5, -5, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = actual_page
    })
    page.left = left_page

    local right_page = Instance.new('frame', {
        size = UDim2.new(0.5, -5, 1, 0),
        position = UDim2.new(0.5, 5, 0, 0),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = actual_page
    })
    page.right = right_page

    local full = Instance.new('frame', {
        size = UDim2.new(1, 0, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = actual_page
    })
    page.full = full

    page.select = function()
        if self.selected_page == page then return end

        if page.index == 1 then
            self.tabs_select:Tween('position', UDim2.new(0, 1, 0, 1), library.tween_duration)
            self.tabs_select:Tween('size', UDim2.new(0, tab.size.X, 1, -2), library.tween_duration)
        else
            self.tabs_select:Tween('position', UDim2.new(0, tab.position.X, 0, 1), library.tween_duration)
            self.tabs_select:Tween('size', UDim2.new(0, tab.size.X, 1, -2), library.tween_duration)
        end

        for _, a_page in pairs(self.pages) do
            if a_page == page then
                a_page.actual_page.visible = true

                a_page.tab_text:Tween('color', library.theme.text, library.tween_duration)
                if a_page.tab_image then a_page.tab_image:Tween('color', library.theme.text, library.tween_duration) end
            else
                a_page.actual_page.visible = false

                a_page.tab_text:Tween('color', library.theme.text_darker, library.tween_duration)
                if a_page.tab_image then a_page.tab_image:Tween('color', library.theme.text_darker, library.tween_duration) end
            end
        end

        self.selected_page = page
    end

    if #self.pages == 1 then
        page.select()
    end
    tab.register(0x01, 'began', page.select)

    return setmetatable(page, {__index = library})
end

library.section = function(self, config)
    local config = {
        title = config.title or 'Section',
        side = config.side or 'left'
    }

    local section = {side = config.side, side_holder = self[config.side]}
    self.sections[#self.sections+1] = section

    local offset = 0
    for _, a_section in pairs(self.sections) do
        if a_section ~= section and a_section.side == config.side then
            offset = offset + a_section.holder.size.Y + 10
        end
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 0),
        position = UDim2.new(0, 0, 0, offset),
        color = library.theme.outline,
        rounding = 4,
        parent = self[config.side]
    })
    section.holder = holder

    Instance.new('frame', {
        size = UDim2.new(1, -2, 0, 28),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.contrast,
        rounding = 4,
        parent = holder
    })

    Instance.new('frame', {
        size = UDim2.new(1, -2, 0, 4),
        position = UDim2.new(0, 1, 0, 25),
        color = library.theme.contrast,
        parent = holder
    })

    Instance.new('frame', {
        size = UDim2.new(1, -2, 0, 4),
        position = UDim2.new(0, 1, 0, 30),
        color = library.theme.contrast_dark,
        parent = holder
    })

    Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -31),
        position = UDim2.new(0, 1, 0, 30),
        color = library.theme.contrast_dark,
        rounding = 4,
        parent = holder
    })

    local title = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 7, 0, 11),
        color = library.theme.text_dark,
        parent = holder
    })

    local actual_section = Instance.new('frame', {
        size = UDim2.new(1, -22, 1, -41),
        position = UDim2.new(0, 11, 0, 40),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = holder
    })
    section.actual_section = actual_section

    return setmetatable(section, {__index = library})
end

library.multi_section = function(self, config)
    local config = {
        sections = config.sections or {'One', 'Two', 'Three'},
        side = config.side or 'left'
    }

    local multisection = {side = config.side, side_holder = self[config.side], sections = {}, selected_section = nil}
    self.sections[#self.sections+1] = multisection

    local offset = 0
    for _, a_section in pairs(self.sections) do
        if a_section ~= multisection and a_section.side == config.side then
            offset = offset + a_section.holder.size.Y + 10
        end
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 0),
        position = UDim2.new(0, 0, 0, offset),
        color = library.theme.outline,
        rounding = 4,
        parent = self[config.side]
    })
    multisection.holder = holder

    local top = Instance.new('frame', {
        size = UDim2.new(1, -2, 0, 28),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.contrast,
        rounding = 4,
        parent = holder
    })

    Instance.new('frame', {
        size = UDim2.new(1, -2, 0, 4),
        position = UDim2.new(0, 1, 0, 25),
        color = library.theme.contrast,
        parent = holder
    })

    Instance.new('frame', {
        size = UDim2.new(1, -2, 0, 4),
        position = UDim2.new(0, 1, 0, 30),
        color = library.theme.contrast_dark,
        parent = holder
    })

    local full = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -31),
        position = UDim2.new(0, 1, 0, 30),
        color = library.theme.contrast_dark,
        rounding = 4,
        parent = holder
    })

    local tabs_select = Instance.new('frame', {
        size = UDim2.new(0, 50, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.accent,
        rounding = 4,
        parent = top
    })

    local tabs_select_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.accent_dark,
        rounding = 4,
        parent = tabs_select
    })

    for _, title in pairs(config.sections) do
        local section = {
            title = config.title,
            width = compatibility.queued_get_text_size(title, library.font) + 12,
            holder = holder,
            side_holder = multisection.side_holder
        }

        local index = #multisection.sections + 1
        multisection.sections[index] = setmetatable(section, {__index = library})

        local tab_offset = 0
        for _, a_section in pairs(multisection.sections) do
            if a_section ~= section then
                tab_offset = tab_offset + a_section.width
            end
        end

        local tab = Instance.new('frame', {
            size = UDim2.new(0, section.width, 1, 0),
            position = UDim2.new(0, tab_offset + 1, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0,
            parent = top
        })
        section.tab = tab

        local tab_text = Instance.new('text', {
            text = title,
            position = UDim2.new(0, 6, 0, 11),
            color = library.theme.text_darker,
            parent = tab
        })
        section.tab_text = tab_text

        local actual_section = Instance.new('frame', {
            size = UDim2.new(1, -22, 1, -41),
            position = UDim2.new(0, 11, 0, 40),
            color = Color3.fromRGB(255, 255, 255),
            alpha = 0,
            visible = false,
            parent = holder
        })
        section.actual_section = actual_section

        local select = function()
            if multisection.selected_section == section then return end

            if index == 1 then
                tabs_select:Tween('position', UDim2.new(0, 1, 0, 1), library.tween_duration)
                tabs_select:Tween('size', UDim2.new(0, tab.size.X, 1, -2), library.tween_duration)
            else
                tabs_select:Tween('position', UDim2.new(0, tab.position.X, 0, 1), library.tween_duration)
                tabs_select:Tween('size', UDim2.new(0, tab.size.X, 1, -2), library.tween_duration)
            end

            for _, a_section in pairs(multisection.sections) do
                if a_section == section then
                    a_section.actual_section.visible = true

                    a_section.tab_text:Tween('color', library.theme.text, library.tween_duration)
                else
                    a_section.actual_section.visible = false

                    a_section.tab_text:Tween('color', library.theme.text_darker, library.tween_duration)
                end
            end

            multisection.selected_section = section
        end

        if index == 1 then
            select()
        end

        tab.register(0x01, 'began', select)
    end

    return unpack(multisection.sections)
end

library.divider = function(self, config)
    local config = {}

    local divider = {
        type = 'divider'
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 4),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local outline = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 4),
        position = UDim2.new(0, 0, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = outline
    })

    return setmetatable(divider, {__index = library})
end

library.toggle = function(self, config)
    local config = {
        title = config.title or 'Toggle',
        unsafe = config.unsafe or false,
        value = config.value or false,
        tip = config.tip or nil,
        flag = config.flag or 'Unset Flag',
        callback = config.callback or function(v) end
    }

    local toggle = {
        type = 'toggle',
        value = config.value
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 16),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 0, 0, 4),
        color = config.unsafe and library.theme.unsafe_dark or library.theme.text_darker,
        parent = holder
    })

    holder.register('hover', 'began', function()
        text:Tween('color', config.unsafe and library.theme.unsafe or library.theme.text, library.tween_duration)
    end)

    holder.register('hover', 'ended', function()
        text:Tween('color', config.unsafe and library.theme.unsafe_dark or library.theme.text_darker, library.tween_duration)
    end)

    local extras = Instance.new('frame', {
        size = UDim2.new(1, 0, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = holder
    })
    toggle.extras = extras

    local toggle_outline = Instance.new('frame', {
        size = UDim2.new(0, 36, 0, 16),
        position = UDim2.new(1, -36, 0, 0),
        color = library.theme.inline,
        rounding = 8,
        parent = extras
    })

    local toggle_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 8,
        parent = toggle_outline
    })

    local toggle_dot_outline = Instance.new('frame', {
        size = UDim2.new(0, 10, 0, 10),
        position = UDim2.new(0, 2, 0, 3),
        color = library.theme.element_darker,
        alpha = 128,
        rounding = 8,
        parent = toggle_outline
    })

    local toggle_dot = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.element_darker,
        rounding = 8,
        parent = toggle_dot_outline
    })

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    toggle.set = function(value)
        toggle.value = value

        if value then
            toggle_dot_outline:Tween('position', UDim2.new(1, -14, 0, 3), library.tween_duration)
            toggle_dot_outline:Tween('color', library.theme.element, library.tween_duration)
            toggle_dot:Tween('color', library.theme.element, library.tween_duration)

            toggle_inner:Tween('color', library.theme.accent_dark, library.tween_duration)
        else
            toggle_dot_outline:Tween('position', UDim2.new(0, 3, 0, 3), library.tween_duration)
            toggle_dot_outline:Tween('color', library.theme.element_darker, library.tween_duration)
            toggle_dot:Tween('color', library.theme.element_darker, library.tween_duration)

            toggle_inner:Tween('color', library.theme.outline, library.tween_duration)
        end

        library.flags[config.flag] = value
        config.callback(value)
    end

    holder.register(0x01, 'began', function()
        toggle.set(not toggle.value)
    end)

    toggle.set(config.value)

    library.elements[config.flag] = toggle
    return setmetatable(toggle, {__index = library})
end

library.slider = function(self, config)
    local config = {
        title = config.title or 'Slider',
        suffix = config.suffix or '',
        value = config.value or 0,
        min = config.min or 0,
        max = config.max or 10,
        float = config.float or 1,
        tip = config.tip or nil,
        flag = config.flag or 'Unset Flag',
        callback = config.callback or function(v) end
    }

    local slider = {
        type = 'slider',
        value = config.value
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 16),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 0, 0, 4),
        color = config.unsafe and library.theme.unsafe_dark or library.theme.text_darker,
        parent = holder
    })

    holder.register('hover', 'began', function()
        text:Tween('color', config.unsafe and library.theme.unsafe or library.theme.text, library.tween_duration)
    end)

    holder.register('hover', 'ended', function()
        text:Tween('color', config.unsafe and library.theme.unsafe_dark or library.theme.text_darker, library.tween_duration)
    end)

    local slider_drag = Instance.new('frame', {
        size = UDim2.new(0, 72, 0, 16),
        position = UDim2.new(1, -72, 0, 0),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = holder
    })

    local slider_outline = Instance.new('frame', {
        size = UDim2.new(0, 72, 0, 4),
        position = UDim2.new(1, -72, 0, 6),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local slider_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = slider_outline
    })

    local slider_number_outline = Instance.new('frame', {
        size = UDim2.new(0, 16, 1, 0),
        position = UDim2.new(1, -78 - 16, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local slider_number_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = slider_number_outline
    })

    local slider_number_text = Instance.new('text', {
        text = config.value,
        position = UDim2.new(0, 0, 0, 4),
        color = library.theme.text,
        parent = slider_number_outline
    })

    local slider_value_outline = Instance.new('frame', {
        size = UDim2.new(0, 2, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = library.theme.accent,
        rounding = 4,
        parent = slider_outline
    })

    local slider_value_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.element,
        rounding = 4,
        parent = slider_value_outline
    })

    local slider_dot_outline = Instance.new('frame', {
        size = UDim2.new(0, 10, 0, 10),
        position = UDim2.new(0, 0, 0, -3),
        color = library.theme.element,
        alpha = 128,
        rounding = 8,
        parent = slider_outline
    })

    local slider_dot = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.element,
        rounding = 8,
        parent = slider_dot_outline
    })

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    slider.set = function(value)
        local rounded = math.floor(value * (1 / config.float) + 0.5) / (1 / config.float)
        local clamped = math.max(config.min, math.min(rounded, config.max))

        slider.value = clamped
        library.flags[config.flag] = clamped
        config.callback(clamped)

        local vwidth = compatibility.queued_get_text_size(tostring(clamped) .. config.suffix, library.font)
        slider_number_outline.size = UDim2.new(0, vwidth + 14, 1, 0)
        slider_number_outline.position = UDim2.new(1, -78 - (vwidth + 14), 0, 0)
        slider_number_text.text = tostring(clamped) .. config.suffix
        slider_number_text.position = UDim2.new(0.5, -(vwidth / 2), 0, 4)

        local scaled = (clamped - config.min) / (config.max - config.min)
        slider_dot_outline:Tween('position', UDim2.new(scaled, -1 + (-9 - -1) * scaled, 0, -3), library.tween_duration)
        slider_value_outline:Tween('size', UDim2.new(scaled, scaled == 0 and 2 or 0, 1, 0), library.tween_duration)
    end

    slider.set(config.value)

    local dragging = false
    slider_drag.register(0x01, 'began', function() dragging = true end)
    slider_drag.register(0x01, 'ended', function() dragging = false end)

    compatibility.update_connection(function()
        if dragging then
            local mouse_pos = compatibility.get_mouse_location()
            local size = (mouse_pos[1] - slider_drag.absolute_position.X) / slider_drag.absolute_size.X
            slider.set(config.min + (size * (config.max - config.min)))
        end
    end)

    library.elements[config.flag] = slider
    return setmetatable(slider, {__index = library})
end

library.dropdown = function(self, config)
    local config = {
        title = config.title or 'Dropdown',
        value = config.value or nil,
        items = config.items or {'One', 'Two', 'Three'},
        flag = config.flag or 'Unset Flag',
        callback = config.callback or function(v) end
    }

    local dropdown = {
        type = 'dropdown',
        value = config.value
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 16),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 0, 0, 4),
        color = config.unsafe and library.theme.unsafe_dark or library.theme.text_darker,
        parent = holder
    })

    holder.register('hover', 'began', function()
        text:Tween('color', config.unsafe and library.theme.unsafe or library.theme.text, library.tween_duration)
    end)

    holder.register('hover', 'ended', function()
        text:Tween('color', config.unsafe and library.theme.unsafe_dark or library.theme.text_darker, library.tween_duration)
    end)

    local values_outline = Instance.new('frame', {
        size = UDim2.new(0, 51, 1, 0),
        position = UDim2.new(1, -51, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local values_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = values_outline
    })

    local values_image = Instance.new('image', {
        size = UDim2.new(0, 12, 0, 12),
        position = UDim2.new(0, 4, 0, 2),
        texture = assets['dropdown'],
        color = library.theme.element,
        parent = values_outline
    })

    local values_text = Instance.new('text', {
        text = 'None',
        position = UDim2.new(0, 19, 0, 4),
        color = library.theme.text,
        parent = values_outline
    })

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    dropdown.set = function(value)
        if value then
            local found = false
            for _, item in pairs(config.items) do
                if item == value then
                    found = true
                    break
                end
            end

            if found then
                dropdown.value = value
                values_text.text = value

                library.flags[config.flag] = value
                config.callback(value)
            else
                dropdown.value = nil
                values_text.text = 'None'

                library.flags[config.flag] = nil
                config.callback(nil)
            end
        else
            dropdown.value = nil
            values_text.text = 'None'

            library.flags[config.flag] = nil
            config.callback(nil)
        end

        local width = compatibility.queued_get_text_size(values_text.text, library.font) + 26
        values_outline.size = UDim2.new(0, width, 1, 0)
        values_outline.position = UDim2.new(1, -width, 0, 0)
    end

    dropdown.set_items = function(items)
        config.items = items

        local f = false
        for _, v in pairs(items) do
            if v == dropdown.value then
                f = true
            end
        end

        if not f then
            dropdown.set(nil)
        end
    end

    values_outline.register(0x01, 'began', function()
        local outside = Instance.new('frame', {
            size = UDim2.new(0, 10000, 0, 10000),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0
        })

        local longest = 0
        for _, item in pairs(config.items) do
            local width = compatibility.queued_get_text_size(item, library.font)
            if width > longest then
                longest = width
            end
        end
        longest = math.max(longest + 12, values_outline.absolute_size.X)

        local outline = Instance.new('frame', {
            size = UDim2.new(0, longest, 0, (#config.items * 17) + 1),
            position = UDim2.new(0, values_outline.absolute_position.X, 0, values_outline.absolute_position.Y + values_outline.absolute_size.Y + 2),
            color = library.theme.inline,
            rounding = 4,
            parent = outside
        })
        outline.register(0x01, 'began', function() end)

        local inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = library.theme.outline,
            rounding = 4,
            parent = outline
        })

        for i, item in pairs(config.items) do
            local bounds = Instance.new('frame', {
                size = UDim2.new(1, 0, 0, 16),
                position = UDim2.new(0, 0, 0, (i - 1) * 17),
                color = Color3.fromRGB(0, 0, 0),
                alpha = 0,
                parent = inner
            })

            local item_text = Instance.new('text', {
                text = item,
                position = UDim2.new(0, 4, 0, 4 + (i - 1) * 17),
                color = dropdown.value == item and library.theme.element_dark or library.theme.text_darker,
                parent = inner
            })

            if i ~= #config.items then
                Instance.new('frame', {
                    size = UDim2.new(1, -8, 0, 1),
                    position = UDim2.new(0, 4, 0, (i * 17) - 1),
                    color = library.theme.inline,
                    parent = inner
                })
            end

            local hovered = false
            bounds.register('hover', 'began', function()
                hovered = true
                if dropdown.value == item then
                    item_text:Tween('color', library.theme.element, library.tween_duration)
                else
                    item_text:Tween('color', library.theme.text, library.tween_duration)
                end
            end)

            bounds.register('hover', 'ended', function()
                hovered = false
                if dropdown.value == item then
                    item_text:Tween('color', library.theme.element_dark, library.tween_duration)
                else
                    item_text:Tween('color', library.theme.text_darker, library.tween_duration)
                end
            end)

            bounds.register(0x01, 'began', function()
                dropdown.set(item)

                local longest = 0
                for _, item in pairs(config.items) do
                    local width = compatibility.queued_get_text_size(item, library.font)
                    if width > longest then
                        longest = width
                    end
                end
                longest = math.max(longest + 12, values_outline.absolute_size.X)

                outline:Tween('size', UDim2.new(0, longest, 0, (#config.items * 17) + 1), library.tween_duration)
                outline:Tween('position', UDim2.new(0, values_outline.absolute_position.X, 0, values_outline.absolute_position.Y + values_outline.absolute_size.Y + 2), library.tween_duration)

                for _, a_item in pairs(inner:GetChildren()) do
                    if a_item.class == 'text' then
                        if a_item.text == item then
                            a_item:Tween('color', library.theme.element, library.tween_duration)
                        else
                            a_item:Tween('color', library.theme.text_darker, library.tween_duration)
                        end
                    end
                end
            end)
        end

        outline.alpha = 0
        outline:Tween('alpha', 255, library.tween_duration)

        for _, v in pairs(outline:GetDescendants()) do
            if v.alpha ~= 0 then
                v.alpha = 0
                v:Tween('alpha', 255, library.tween_duration)
            end
        end

        outside.register(0x01, 'began', function()
            outside:Destroy()
            outline:Destroy()
        end)
    end)

    dropdown.set(config.value)

    library.elements[config.flag] = dropdown
    return setmetatable(dropdown, {__index = library})
end

library.multi_dropdown = function(self, config)
    local config = {
        title = config.title or 'Dropdown',
        value = config.value or nil,
        items = config.items or {'One', 'Two', 'Three'},
        flag = config.flag or 'Unset Flag',
        selections = config.selections or 3,
        callback = config.callback or function(v) end
    }

    local dropdown = {
        type = 'dropdown',
        value = {}
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 16),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0, 0, 0, 4),
        color = config.unsafe and library.theme.unsafe_dark or library.theme.text_darker,
        parent = holder
    })

    holder.register('hover', 'began', function()
        text:Tween('color', config.unsafe and library.theme.unsafe or library.theme.text, library.tween_duration)
    end)

    holder.register('hover', 'ended', function()
        text:Tween('color', config.unsafe and library.theme.unsafe_dark or library.theme.text_darker, library.tween_duration)
    end)

    local values_outline = Instance.new('frame', {
        size = UDim2.new(0, 51, 1, 0),
        position = UDim2.new(1, -51, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local values_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = values_outline
    })

    local values_image = Instance.new('image', {
        size = UDim2.new(0, 12, 0, 12),
        position = UDim2.new(0, 4, 0, 2),
        texture = assets['dropdown'],
        color = library.theme.element,
        parent = values_outline
    })

    local values_text = Instance.new('text', {
        text = 'None',
        position = UDim2.new(0, 19, 0, 4),
        color = library.theme.text,
        parent = values_outline
    })

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    dropdown.set = function(val)
        if type(val) == 'table' then
            dropdown.value = val

            library.flags[config.flag] = val
            config.callback(val)

            if #dropdown.value > 0 then
                if #dropdown.value > config.selections then
                    values_text.text = #dropdown.value .. ' Selected'
                else
                    local order = {}
                    for i, v in pairs(config.items) do
                        order[v] = i
                    end

                    table.sort(dropdown.value, function(a, b)
                        return (order[a] or math.huge) < (order[b] or math.huge)
                    end)

                    values_text.text = table.concat(dropdown.value, ', ')
                end
            else
                values_text.text = 'None'
            end
        else
            local found = false
            for i, v in pairs(dropdown.value) do
                if v == val then
                    found = true
                    table.remove(dropdown.value, i)
                    break
                end
            end

            if not found then
                table.insert(dropdown.value, val)
            end

            library.flags[config.flag] = dropdown.value
            config.callback(dropdown.value)

            if #dropdown.value > 0 then
                if #dropdown.value > config.selections then
                    values_text.text = #dropdown.value .. ' Selected'
                else
                    local order = {}
                    for i, v in pairs(config.items) do
                        order[v] = i
                    end

                    table.sort(dropdown.value, function(a, b)
                        return (order[a] or math.huge) < (order[b] or math.huge)
                    end)

                    values_text.text = table.concat(dropdown.value, ', ')
                end
            else
                values_text.text = 'None'
            end
        end

        local width = compatibility.queued_get_text_size(values_text.text, library.font) + 26
        values_outline.size = UDim2.new(0, width, 1, 0)
        values_outline.position = UDim2.new(1, -width, 0, 0)
    end

    dropdown.set_items = function(items)
        config.items = items

        for _, value in pairs(dropdown.value) do
            local found = false
            for _, item in pairs(items) do
                if item == value then
                    found = true
                    break
                end
            end

            if not found then
                dropdown.set(value)
            end
        end
    end

    values_outline.register(0x01, 'began', function()
        local outside = Instance.new('frame', {
            size = UDim2.new(0, 10000, 0, 10000),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0
        })

        local longest = 0
        for _, item in pairs(config.items) do
            local width = compatibility.queued_get_text_size(item, library.font)
            if width > longest then
                longest = width
            end
        end
        longest = math.max(longest + 12, values_outline.absolute_size.X)

        local outline = Instance.new('frame', {
            size = UDim2.new(0, longest, 0, (#config.items * 17) + 1),
            position = UDim2.new(0, values_outline.absolute_position.X, 0, values_outline.absolute_position.Y + values_outline.absolute_size.Y + 2),
            color = library.theme.inline,
            rounding = 4,
            parent = outside
        })
        outline.register(0x01, 'began', function() end)

        local inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = library.theme.outline,
            rounding = 4,
            parent = outline
        })

        for i, item in pairs(config.items) do
            local bounds = Instance.new('frame', {
                size = UDim2.new(1, 0, 0, 16),
                position = UDim2.new(0, 0, 0, (i - 1) * 17),
                color = Color3.fromRGB(0, 0, 0),
                alpha = 0,
                parent = inner
            })

            local found = false
            for _, v in pairs(dropdown.value) do
                if v == item then
                    found = true
                    break
                end
            end

            local item_text = Instance.new('text', {
                text = item,
                position = UDim2.new(0, 4, 0, 4 + (i - 1) * 17),
                color = found and library.theme.element_dark or library.theme.text_darker,
                parent = inner
            })

            if i ~= #config.items then
                Instance.new('frame', {
                    size = UDim2.new(1, -8, 0, 1),
                    position = UDim2.new(0, 4, 0, (i * 17) - 1),
                    color = library.theme.inline,
                    parent = inner
                })
            end

            local hovered = false
            bounds.register('hover', 'began', function()
                hovered = true

                local found = false
                for _, v in pairs(dropdown.value) do
                    if v == item then
                        found = true
                        break
                    end
                end

                if found then
                    item_text:Tween('color', library.theme.element, library.tween_duration)
                else
                    item_text:Tween('color', library.theme.text, library.tween_duration)
                end
            end)

            bounds.register('hover', 'ended', function()
                hovered = false

                local found = false
                for _, v in pairs(dropdown.value) do
                    if v == item then
                        found = true
                        break
                    end
                end

                if found then
                    item_text:Tween('color', library.theme.element_dark, library.tween_duration)
                else
                    item_text:Tween('color', library.theme.text_darker, library.tween_duration)
                end
            end)

            bounds.register(0x01, 'began', function()
                dropdown.set(item)

                local longest = 0
                for _, item in pairs(config.items) do
                    local width = compatibility.queued_get_text_size(item, library.font)
                    if width > longest then
                        longest = width
                    end
                end
                longest = math.max(longest + 12, values_outline.absolute_size.X)

                outline:Tween('size', UDim2.new(0, longest, 0, (#config.items * 17) + 1), library.tween_duration)
                outline:Tween('position', UDim2.new(0, values_outline.absolute_position.X, 0, values_outline.absolute_position.Y + values_outline.absolute_size.Y + 2), library.tween_duration)

                for _, a_item in pairs(inner:GetChildren()) do
                    if a_item.class == 'text' then
                        local found = false
                        for _, v in pairs(dropdown.value) do
                            if v == a_item.text then
                                found = true
                                break
                            end
                        end

                        if found then
                            if a_item.text == item then
                                a_item:Tween('color', library.theme.element, library.tween_duration)
                            else
                                a_item:Tween('color', library.theme.element_dark, library.tween_duration)
                            end
                        else
                            if a_item.text == item then
                                a_item:Tween('color', library.theme.text, library.tween_duration)
                            else
                                a_item:Tween('color', library.theme.text_darker, library.tween_duration)
                            end
                        end
                    end
                end
            end)
        end

        outline.alpha = 0
        outline:Tween('alpha', 255, library.tween_duration)

        for _, v in pairs(outline:GetDescendants()) do
            if v.alpha ~= 0 then
                v.alpha = 0
                v:Tween('alpha', 255, library.tween_duration)
            end
        end

        outside.register(0x01, 'began', function()
            outside:Destroy()
            outline:Destroy()
        end)
    end)

    dropdown.set(config.value)

    library.elements[config.flag] = dropdown
    return setmetatable(dropdown, {__index = library})
end

library.button = function(self, config)
    local config = {
        title = config.title or 'Button',
        callback = config.callback or function(v) end
    }

    local button = {
        type = 'button',
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 16),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local values_outline = Instance.new('frame', {
        size = UDim2.new(1, 0, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local values_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = values_outline
    })

    local width = compatibility.queued_get_text_size(config.title, library.font)
    local values_text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0.5, -(width / 2), 0, 4),
        color = library.theme.text_darker,
        parent = values_outline
    })

    local hovered = false
    holder.register('hover', 'began', function()
        values_text:Tween('color', library.theme.text, library.tween_duration)
        hovered = true
    end)

    holder.register('hover', 'ended', function()
        values_text:Tween('color', library.theme.text_darker, library.tween_duration)
        hovered = false
    end)

    local clicked = nil
    holder.register(0x01, 'began', function()
        clicked = compatibility.tick()
        values_text:Tween('color', library.theme.element, library.tween_duration)
        config.callback()
    end)

    compatibility.update_connection(function()
        if clicked then
            local delta = compatibility.tick() - clicked
            if delta >= library.tween_duration then
                clicked = nil
                if hovered then
                    values_text:Tween('color', library.theme.text, library.tween_duration)
                else
                    values_text:Tween('color', library.theme.text_darker, library.tween_duration)
                end
            end
        end
    end)

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    return setmetatable(button, {__index = library})
end

library.textbox = function(self, config)
    local config = {
        flag = config.flag or 'Unset Flag',
        title = config.title or 'Textbox',
        value = config.value or '',
        callback = config.callback or function(v) end
    }

    local textbox = {
        type = 'textbox',
        value = config.value
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, 16),
        position = UDim2.new(0, 0, 0, offset),
        color = Color3.fromRGB(255, 255, 255),
        alpha = 0,
        parent = self.actual_section
    })

    local values_outline = Instance.new('frame', {
        size = UDim2.new(1, 0, 1, 0),
        position = UDim2.new(0, 0, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = holder
    })

    local values_inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = values_outline
    })

    local width = compatibility.queued_get_text_size(config.title, library.font)
    local values_text = Instance.new('text', {
        text = config.title,
        position = UDim2.new(0.5, -(width / 2), 0, 4),
        color = library.theme.text_darker,
        parent = values_outline
    })

    local typing_bar = Instance.new('frame', {
        size = UDim2.new(0, 2, 1, -4),
        position = UDim2.new(0, 1, 0, 1),
        color = Color3.fromRGB(255, 255, 255),
        rounding = 0,
        visible = false,
        parent = values_outline
    })

    local listening = false
    holder.register(0x01, 'began', function()
        typing_bar.visible = true
        listening = true
        values_text:Tween('color', library.theme.text, library.tween_duration)
    end)

    local hovered = false
    holder.register('hover', 'began', function()
        values_text:Tween('color', library.theme.text, library.tween_duration)
    end)

    holder.register('hover', 'ended', function()
        if not listening then
            values_text:Tween('color', library.theme.text_darker, library.tween_duration)
        end
        hovered = false
    end)

    textbox.set = function(v)
        textbox.value = v
        library.flags[config.flag] = v
        config.callback(v)

        if #v == 0 then
            values_text.text = config.title

            local width = compatibility.queued_get_text_size(config.title, library.font)
            values_text.position = UDim2.new(0.5, -(width / 2), 0, 4)

            typing_bar.position = UDim2.new(0.5, 0, 0, 2)
        else
            values_text.text = v

            local width = compatibility.queued_get_text_size(v, library.font)
            values_text.position = UDim2.new(0.5, -(width / 2), 0, 4)

            typing_bar.position = UDim2.new(0.5, (width / 2) + 1, 0, 2)
        end
    end

    local text_keys = {
        [0x30] = '0',
        [0x31] = '1',
        [0x32] = '2',
        [0x33] = '3',
        [0x34] = '4',
        [0x35] = '5',
        [0x36] = '6',
        [0x37] = '7',
        [0x38] = '8',
        [0x39] = '9',

        [0x41] = 'A',
        [0x42] = 'B',
        [0x43] = 'C',
        [0x44] = 'D',
        [0x45] = 'E',
        [0x46] = 'F',
        [0x47] = 'G',
        [0x48] = 'H',
        [0x49] = 'I',
        [0x4A] = 'J',
        [0x4B] = 'K',
        [0x4C] = 'L',
        [0x4D] = 'M',
        [0x4E] = 'N',
        [0x4F] = 'O',
        [0x50] = 'P',
        [0x51] = 'Q',
        [0x52] = 'R',
        [0x53] = 'S',
        [0x54] = 'T',
        [0x55] = 'U',
        [0x56] = 'V',
        [0x57] = 'W',
        [0x58] = 'X',
        [0x59] = 'Y',
        [0x5A] = 'Z',

        -- [0xBD] = '_',
        [0x20] = ' '
    }

    local last_keys = {}
    compatibility.update_connection(function()
        if listening then
            if compatibility.is_key_pressed(0x01) then
                local mouse_pos = compatibility.get_mouse_location()
                if not library.mouse_over(mouse_pos, holder) then
                    if not hovered then
                        values_text:Tween('color', library.theme.text_darker, library.tween_duration)
                    end
                    listening = false
                    typing_bar.visible = false
                    return
                end
            end

            if compatibility.is_key_pressed(0x0D) or compatibility.is_key_pressed(0x1B) then
                if not hovered then
                    values_text:Tween('color', library.theme.text_darker, library.tween_duration)
                end
                listening = false
                typing_bar.visible = false
                return
            end

            local shift = compatibility.is_key_pressed(0xA0)
            local backspace = compatibility.is_key_pressed(0x08)

            if backspace then
                if not last_keys[0x08] then
                    last_keys[0x08] = true
                    textbox.set(string.sub(textbox.value, 1, #textbox.value - 1))
                end
            else
                last_keys[0x08] = nil
            end

            local current_keys = {}
            for i, v in pairs(text_keys) do
                local pressed = compatibility.is_key_pressed(i)
                current_keys[i] = pressed and true or nil

                if pressed and not last_keys[i] then
                    last_keys[i] = true

                    local val = shift and v or string.lower(v)
                    textbox.set(textbox.value .. val)
                end
            end

            for i, v in pairs(last_keys) do
                if i ~= 0x08 then
                    if not current_keys[i] then
                        last_keys[i] = nil
                    end
                end
            end
        end
    end)

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    textbox.set(config.value)
    return setmetatable(textbox, {__index = library})
end

library.list = function(self, config)
    local config = {
        length = config.length or 200,
        items = config.items or {},
        flag = config.flag or 'Unset Flag',
        callback = config.callback or function(v) end
    }

    local list = {
        type = 'list',
        items = {},
        value = nil
    }

    local offset = 0
    for _, element in pairs(self.actual_section:GetChildren()) do
        offset = offset + element.size.Y + 10
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(1, 0, 0, config.length),
        position = UDim2.new(0, 0, 0, offset),
        color = library.theme.inline,
        rounding = 4,
        parent = self.actual_section
    })

    local inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = holder
    })

    local c = math.floor(config.length / 17)
    for i = 1, c do
        Instance.new('frame', {
            size = UDim2.new(1, -8, 0, 1),
            position = UDim2.new(0, 4, 0, (i * 17) - 1),
            color = library.theme.inline,
            parent = inner
        })
    end

    if self.holder.size.Y < offset + 51 + holder.size.Y then
        self.holder.size = UDim2.new(1, 0, 0, offset + 51 + holder.size.Y)
    end

    local section_offset = 0
    for _, child in pairs(self.side_holder:GetChildren()) do
        child.position = UDim2.new(0, 0, 0, section_offset)
        section_offset = section_offset + child.size.Y + 10
    end

    list.set = function(item, hovered)
        for _, entry in pairs(list.items) do
            if entry.item == item then
                if hovered then
                    entry.text:Tween('color', library.theme.element, library.tween_duration)
                else
                    entry.text:Tween('color', library.theme.element_dark, library.tween_duration)
                end

                list.value = item
                library.flags[config.flag] = item
                config.callback(item)
            else
                entry.text:Tween('color', library.theme.text_darker, library.tween_duration)
            end
        end
    end

    list.add = function(item)
        for _, entry in pairs(list.items) do
            if entry.item == item then
                return
            end
        end

        local bounds = Instance.new('frame', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 0, #list.items * 17),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0,
            parent = inner
        })

        local item_text = Instance.new('text', {
            text = item,
            position = UDim2.new(0, 4, 0, 4),
            color = library.theme.text_darker,
            parent = bounds
        })

        local hovered = false
        bounds.register(0x01, 'began', function()
            list.set(item, hovered)
        end)

        bounds.register('hover', 'began', function()
            hovered = true
            if list.value == item then
                item_text:Tween('color', library.theme.element, library.tween_duration)
            else
                item_text:Tween('color', library.theme.text, library.tween_duration)
            end
        end)

        bounds.register('hover', 'ended', function()
            hovered = false
            if list.value == item then
                item_text:Tween('color', library.theme.element_dark, library.tween_duration)
            else
                item_text:Tween('color', library.theme.text_darker, library.tween_duration)
            end
        end)

        table.insert(list.items, {item = item, holder = bounds, text = item_text})
    end

    list.remove = function(item)
        for i, entry in pairs(list.items) do
            if entry.item == item then
                entry.holder:Destroy()
                table.remove(list.items, i)
            end
        end

        for i, entry in pairs(list.items) do
            entry.holder.position = UDim2.new(0, 0, 0, (i - 1) * 17)
        end

        list.value = nil
        library.flags[config.flag] = nil
        config.callback(nil)
    end

    list.clear = function()
        for _, entry in pairs(list.items) do
            entry.holder:Destroy()
        end

        list.items = {}

        list.value = nil
        library.flags[config.flag] = nil
        config.callback(nil)
    end

    for _, item in pairs(config.items) do
        list.add(item)
    end

    library.elements[config.flag] = list
    return setmetatable(list, {__index = library})
end

library.colorpicker = function(self, config)
    local config = {
        color = config.color or Color3.fromRGB(255, 0, 0),
        alpha = config.alpha or 255,
        flag = config.flag or 'Unset Flag',
        callback = config.callback or function(v) end
    }

    local colorpicker = {
        type = 'colorpicker',
        value = {color = config.color, alpha = config.alpha}
    }

    local offset = -20
    for _, element in pairs(self.extras:GetChildren()) do
        local position = element.position
        element.position = UDim2.new(position.Width, position.X + offset, position.Height, position.Y)
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(0, 16, 0, 16),
        position = UDim2.new(1, -16, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = self.extras
    })

    local inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = holder
    })

    local image = Instance.new('image', {
        size = UDim2.new(0, 12, 0, 12),
        position = UDim2.new(0, 1, 0, 1),
        color = Color3.fromRGB(255, 255, 255),
        texture = assets['brush'],
        parent = inner
    })

    local dragging_hue, dragging_alpha, dragging_saturation = false, false, false
    local h, s, v = config.color:ToHSV()

    colorpicker.set = function(value)
        if value.color then
            colorpicker.value.color = value.color
        end

        if value.alpha then
            colorpicker.value.alpha = value.alpha
        end

        image.color = colorpicker.value.color
        image.alpha = colorpicker.value.alpha

        library.flags[config.flag] = colorpicker.value
        config.callback(colorpicker.value)

        h, s, v = colorpicker.value.color:ToHSV()

        h = math.min(math.max(h, 0.001), 0.999)
        s = math.min(math.max(s, 0.001), 0.999)
        v = math.min(math.max(v, 0.001), 0.999)
    end

    colorpicker.set({color = config.color, alpha = config.alpha})

    local refresh = nil
    local frames = {}
    holder.register(0x01, 'began', function()
        local outside = Instance.new('frame', {
            size = UDim2.new(0, 10000, 0, 10000),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0
        })

        local picker_holder = Instance.new('frame', {
            size = UDim2.new(0, 250, 0, 170),
            position = UDim2.new(0, holder.absolute_position.X + 18, 0, holder.absolute_position.Y),
            rounding = 4,
            color = library.theme.inline
        })
        picker_holder.register(0x01, 'began', function() end)

        local picker_inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = library.theme.contrast_dark,
            rounding = 4,
            parent = picker_holder
        })

        local saturation_background = Instance.new('frame', {
            size = UDim2.new(1, -8, 0, 120),
            position = UDim2.new(0, 4, 0, 4),
            color = Color3.fromRGB(255, 255, 255),
            parent = picker_inner
        })
        frames.saturation_background = saturation_background

        saturation_background.register(0x01, 'began', function()
            dragging_saturation = true
        end)

        saturation_background.register(0x01, 'ended', function()
            dragging_saturation = false
        end)

        local saturation_image = Instance.new('image', {
            size = UDim2.new(1, 0, 1, 0),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(255, 0, 0),
            texture = assets['saturation'],
            parent = saturation_background
        })

        local saturation_picker = Instance.new('frame', {
            size = UDim2.new(0, 6, 0, 6),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            rounding = 50,
            parent = saturation_image
        })

        local saturation_picker_inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = Color3.fromRGB(255, 255, 255),
            rounding = 50,
            parent = saturation_picker
        })

        local hue_image = Instance.new('image', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 1, 4),
            color = Color3.fromRGB(255, 255, 255),
            texture = assets['hue'],
            parent = saturation_background
        })
        frames.hue_image = hue_image

        hue_image.register(0x01, 'began', function()
            dragging_hue = true
        end)

        hue_image.register(0x01, 'ended', function()
            dragging_hue = false
        end)

        local hue_picker = Instance.new('frame', {
            size = UDim2.new(0, 6, 1, 0),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            rounding = 50,
            parent = hue_image
        })

        local hue_picker_inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = Color3.fromRGB(255, 255, 255),
            rounding = 50,
            parent = hue_picker
        })

        local alpha_gradient = Instance.new('gradient', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 1, 4),
            start = Color3.fromRGB(255, 255, 255),
            finish = library.theme.contrast_dark,
            horizontal = true,
            parent = hue_image
        })
        frames.alpha_gradient = alpha_gradient

        alpha_gradient.register(0x01, 'began', function()
            dragging_alpha = true
        end)

        alpha_gradient.register(0x01, 'ended', function()
            dragging_alpha = false
        end)

        local alpha_picker = Instance.new('frame', {
            size = UDim2.new(0, 6, 1, 0),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            rounding = 50,
            parent = alpha_gradient
        })

        local alpha_picker_inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = Color3.fromRGB(255, 255, 255),
            rounding = 50,
            parent = alpha_picker
        })

        do -- corner drawings
            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(0, 0, 0, 0),
                color = library.theme.contrast_dark,
                parent = saturation_background
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(1, -1, 0, 0),
                color = library.theme.contrast_dark,
                parent = saturation_background
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(1, -1, 1, -1),
                color = library.theme.contrast_dark,
                parent = saturation_background
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(0, 0, 1, -1),
                color = library.theme.contrast_dark,
                parent = saturation_background
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(0, 0, 0, 0),
                color = library.theme.contrast_dark,
                parent = hue_image
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(1, -1, 0, 0),
                color = library.theme.contrast_dark,
                parent = hue_image
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(1, -1, 1, -1),
                color = library.theme.contrast_dark,
                parent = hue_image
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(0, 0, 1, -1),
                color = library.theme.contrast_dark,
                parent = hue_image
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(0, 0, 0, 0),
                color = library.theme.contrast_dark,
                parent = alpha_gradient
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(1, -1, 0, 0),
                color = library.theme.contrast_dark,
                parent = alpha_gradient
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(1, -1, 1, -1),
                color = library.theme.contrast_dark,
                parent = alpha_gradient
            })

            Instance.new('frame', {
                size = UDim2.new(0, 1, 0, 1),
                position = UDim2.new(0, 0, 1, -1),
                color = library.theme.contrast_dark,
                parent = alpha_gradient
            })
        end

        refresh = function()
            alpha_gradient.start = Color3.fromHSV(h, s, v)
            saturation_image.color = Color3.fromHSV(h, 1, 1)

            hue_picker.position = UDim2.new(h, -5 * (h), 0, 0)

            local alpha = colorpicker.value.alpha
            alpha_picker.position = UDim2.new(1 - (alpha / 255), -5 * (1 - (alpha / 255)), 0, 0)

            local sat_x = s >= 1 and -5 or -5 * s
            local sat_y = v <= 0 and -5 or -5 * (1 - v)
            saturation_picker.position = UDim2.new(s, sat_x, 1 - v, sat_y)
        end

        refresh()

        outside.register(0x01, 'began', function()
            frames = {}
            refresh = nil

            outside:Destroy()
            picker_holder:Destroy()
        end)
    end)

    compatibility.update_connection(function()
        if refresh then
            local mouse_pos = compatibility.get_mouse_location()

            if dragging_saturation then
                local x = (mouse_pos[1] - frames.saturation_background.absolute_position.X) / frames.saturation_background.absolute_size.X
                local y = (mouse_pos[2] - frames.saturation_background.absolute_position.Y) / frames.saturation_background.absolute_size.Y

                y = 1 - y

                colorpicker.set({color = Color3.fromHSV(h, x, y)})
                refresh()
            end

            if dragging_hue then
                local y = (mouse_pos[1] - frames.hue_image.absolute_position.X) / frames.hue_image.absolute_size.X
                colorpicker.set({color = Color3.fromHSV(y, s, v)})
                refresh()
            end

            if dragging_alpha then
                local x = (mouse_pos[1] - frames.alpha_gradient.absolute_position.X) / frames.alpha_gradient.absolute_size.X
                x = 1 - math.min(math.max(x, 0), 0.999)

                colorpicker.set({alpha = x * 255})
                refresh()
            end
        end
    end)

    library.elements[config.flag] = colorpicker
    return setmetatable(colorpicker, {__index = library})
end

library.keypicker = function(self, config)
    local config = {
        key = config.key or nil,
        mode = config.mode or 'Toggle',
        flag = config.flag or 'Unset Flag',
        callback = config.callback or function(v) end
    }

    local keypicker = {
        type = 'keypicker',
        value = {key = config.key, mode = config.mode}
    }

    local offset = -39
    for _, element in pairs(self.extras:GetChildren()) do
        local position = element.position
        element.position = UDim2.new(position.Width, position.X + offset, position.Height, position.Y)
    end

    local holder = Instance.new('frame', {
        size = UDim2.new(0, 35, 0, 16),
        position = UDim2.new(1, -35, 0, 0),
        color = library.theme.inline,
        rounding = 4,
        parent = self.extras
    })

    local inner = Instance.new('frame', {
        size = UDim2.new(1, -2, 1, -2),
        position = UDim2.new(0, 1, 0, 1),
        color = library.theme.outline,
        rounding = 4,
        parent = holder
    })

    local key_text = Instance.new('text', {
        text = 'None',
        position = UDim2.new(0, 4, 0, 3),
        color = library.theme.text,
        parent = inner
    })

    keypicker.set = function(value)
        if value.key then
            local name = keycodes[value.key]

            local width = compatibility.queued_get_text_size(name, library.font)
            holder.size = UDim2.new(0, width + 10, 0, 16)

            key_text.text = name

            local offset = 0
            for i = #self.extras.children, 1, -1 do
                local element = self.extras.children[i]
                local width = element.size.X

                offset = offset + width
                element.position = UDim2.new(1, -offset, element.position.Height, element.position.Y)

                offset = offset + 4
            end

            library.flags[config.flag] = false
            config.callback(false)

            keypicker.value.key = value.key
        end

        if value.mode then
            library.flags[config.flag] = false
            config.callback(false)

            keypicker.value.mode = value.mode
        end
    end

    keypicker.set({key = config.key, mode = config.mode})

    local listening = false
    holder.register(0x01, 'began', function()
        listening = true

        local name = '...'

        local width = compatibility.queued_get_text_size(name, library.font)
        holder.size = UDim2.new(0, width + 10, 0, 16)

        key_text.text = name

        local offset = 0
        for i = #self.extras.children, 1, -1 do
            local element = self.extras.children[i]
            local width = element.size.X

            offset = offset + width
            element.position = UDim2.new(1, -offset, element.position.Height, element.position.Y)

            offset = offset + 4
        end
    end)

    holder.register(0x02, 'began', function()
        local outside = Instance.new('frame', {
            size = UDim2.new(0, 10000, 0, 10000),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0
        })

        local outline = Instance.new('frame', {
            size = UDim2.new(0, 53, 0, 69),
            position = UDim2.new(0, holder.absolute_position.X + holder.absolute_size.X + 2, 0, holder.absolute_position.Y),
            color = library.theme.inline,
            rounding = 4,
            parent = outside
        })
        outline.register(0x01, 'began', function() end)

        local inner = Instance.new('frame', {
            size = UDim2.new(1, -2, 1, -2),
            position = UDim2.new(0, 1, 0, 1),
            color = library.theme.outline,
            rounding = 4,
            parent = outline
        })

        local always_bounds = Instance.new('frame', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 0, 0),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0,
            parent = inner
        })

        local always_text = Instance.new('text', {
            text = 'Always',
            position = UDim2.new(0, 4, 0, 4),
            color = keypicker.value.mode == 'Always' and library.theme.element_dark or library.theme.text_darker,
            parent = inner
        })

        local toggle_bounds = Instance.new('frame', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 0, 17),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0,
            parent = inner
        })

        local toggle_text = Instance.new('text', {
            text = 'Toggle',
            position = UDim2.new(0, 4, 0, 4 + 17),
            color = keypicker.value.mode == 'Toggle' and library.theme.element_dark or library.theme.text_darker,
            parent = inner
        })

        local on_hold_bounds = Instance.new('frame', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 0, 34),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0,
            parent = inner
        })

        local on_hold_text = Instance.new('text', {
            text = 'On Hold',
            position = UDim2.new(0, 4, 0, 4 + 34),
            color = keypicker.value.mode == 'On Hold' and library.theme.element_dark or library.theme.text_darker,
            parent = inner
        })

        local off_hold_bounds = Instance.new('frame', {
            size = UDim2.new(1, 0, 0, 16),
            position = UDim2.new(0, 0, 0, 51),
            color = Color3.fromRGB(0, 0, 0),
            alpha = 0,
            parent = inner
        })

        local off_hold_text = Instance.new('text', {
            text = 'Off Hold',
            position = UDim2.new(0, 4, 0, 4 + 51),
            color = keypicker.value.mode == 'Off Hold' and library.theme.element_dark or library.theme.text_darker,
            parent = inner
        })

        for i = 1, 3 do
            Instance.new('frame', {
                size = UDim2.new(1, -8, 0, 1),
                position = UDim2.new(0, 4, 0, (i * 17) - 1),
                color = library.theme.inline,
                parent = inner
            })
        end

        always_bounds.register('hover', 'began', function()
            if keypicker.value.mode == 'Always' then
                always_text:Tween('color', library.theme.element, library.tween_duration)
            else
                always_text:Tween('color', library.theme.text, library.tween_duration)
            end
        end)

        always_bounds.register('hover', 'ended', function()
            if keypicker.value.mode == 'Always' then
                always_text:Tween('color', library.theme.element_dark, library.tween_duration)
            else
                always_text:Tween('color', library.theme.text_darker, library.tween_duration)
            end
        end)

        always_bounds.register(0x01, 'began', function()
            keypicker.set({mode = 'Always'})
            always_text:Tween('color', library.theme.element, library.tween_duration)
            toggle_text:Tween('color', library.theme.text_darker, library.tween_duration)
            on_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
            off_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
        end)

        toggle_bounds.register('hover', 'began', function()
            if keypicker.value.mode == 'Toggle' then
                toggle_text:Tween('color', library.theme.element, library.tween_duration)
            else
                toggle_text:Tween('color', library.theme.text, library.tween_duration)
            end
        end)

        toggle_bounds.register('hover', 'ended', function()
            if keypicker.value.mode == 'Toggle' then
                toggle_text:Tween('color', library.theme.element_dark, library.tween_duration)
            else
                toggle_text:Tween('color', library.theme.text_darker, library.tween_duration)
            end
        end)

        toggle_bounds.register(0x01, 'began', function()
            keypicker.set({mode = 'Toggle'})
            toggle_text:Tween('color', library.theme.element, library.tween_duration)
            always_text:Tween('color', library.theme.text_darker, library.tween_duration)
            on_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
            off_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
        end)

        on_hold_bounds.register('hover', 'began', function()
            if keypicker.value.mode == 'On Hold' then
                on_hold_text:Tween('color', library.theme.element, library.tween_duration)
            else
                on_hold_text:Tween('color', library.theme.text, library.tween_duration)
            end
        end)

        on_hold_bounds.register('hover', 'ended', function()
            if keypicker.value.mode == 'On Hold' then
                on_hold_text:Tween('color', library.theme.element_dark, library.tween_duration)
            else
                on_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
            end
        end)

        on_hold_bounds.register(0x01, 'began', function()
            keypicker.set({mode = 'On Hold'})
            on_hold_text:Tween('color', library.theme.element, library.tween_duration)
            always_text:Tween('color', library.theme.text_darker, library.tween_duration)
            toggle_text:Tween('color', library.theme.text_darker, library.tween_duration)
            off_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
        end)

        off_hold_bounds.register('hover', 'began', function()
            if keypicker.value.mode == 'Off Hold' then
                off_hold_text:Tween('color', library.theme.element, library.tween_duration)
            else
                off_hold_text:Tween('color', library.theme.text, library.tween_duration)
            end
        end)

        off_hold_bounds.register('hover', 'ended', function()
            if keypicker.value.mode == 'Off Hold' then
                off_hold_text:Tween('color', library.theme.element_dark, library.tween_duration)
            else
                off_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
            end
        end)

        off_hold_bounds.register(0x01, 'began', function()
            keypicker.set({mode = 'Off Hold'})
            off_hold_text:Tween('color', library.theme.element, library.tween_duration)
            always_text:Tween('color', library.theme.text_darker, library.tween_duration)
            toggle_text:Tween('color', library.theme.text_darker, library.tween_duration)
            on_hold_text:Tween('color', library.theme.text_darker, library.tween_duration)
        end)

        outline.alpha = 0
        outline:Tween('alpha', 255, library.tween_duration)

        for _, v in pairs(outline:GetDescendants()) do
            if v.alpha ~= 0 then
                v.alpha = 0
                v:Tween('alpha', 255, library.tween_duration)
            end
        end

        outside.register(0x01, 'began', function()
            outside:Destroy()
            outline:Destroy()
        end)
    end)

    local last_keys = {}
    compatibility.update_connection(function()
        if listening then
            if compatibility.is_key_pressed(0x1B) or compatibility.is_key_pressed(0x08) then
                local name = 'None'

                local width = compatibility.queued_get_text_size(name, library.font)
                holder.size = UDim2.new(0, width + 10, 0, 16)

                key_text.text = name

                local offset = 0
                for i = #self.extras.children, 1, -1 do
                    local element = self.extras.children[i]
                    local width = element.size.X

                    offset = offset + width
                    element.position = UDim2.new(1, -offset, element.position.Height, element.position.Y)

                    offset = offset + 4
                end

                library.flags[config.flag] = false
                config.callback(false)
                keypicker.value.key = nil

                listening = false
            else
                for keycode in pairs(keycodes) do
                    if compatibility.is_key_pressed(keycode) then
                        keypicker.set({key = keycode})
                        listening = false
                        break
                    end
                end
            end
        end

        local key = keypicker.value.key
        if key then
            local pressed = compatibility.is_key_pressed(key)
            local mode = keypicker.value.mode

            if mode == 'Always' then
                library.flags[config.flag] = true
                config.callback(true)
                return
            end

            if pressed then
                if mode == 'Toggle' then
                    if not last_keys[key] then
                        if library.flags[config.flag] then
                            library.flags[config.flag] = false
                            config.callback(false)
                        else
                            library.flags[config.flag] = true
                            config.callback(true)
                        end
                    end
                elseif mode == 'On Hold' then
                    library.flags[config.flag] = true
                    config.callback(true)
                elseif mode == 'Off Hold' then
                    library.flags[config.flag] = false
                    config.callback(false)
                end
            else
                if mode == 'On Hold' then
                    library.flags[config.flag] = false
                    config.callback(false)
                elseif mode == 'Off Hold' then
                    library.flags[config.flag] = true
                    config.callback(true)
                end
            end

            last_keys[key] = pressed
        else
            if keypicker.value.mode == 'Always' then
                library.flags[config.flag] = true
                config.callback(true)
            else
                library.flags[config.flag] = false
                config.callback(false)
            end
        end
    end)

    library.elements[config.flag] = keypicker
    return setmetatable(keypicker, {__index = library})
end

local last_pressed, last_hovered = {}, {}
compatibility.update_connection(function()
    if not compatibility.get_menu_state() then return end

    local mouse_pos = compatibility.get_mouse_location()

    local pressed = {
        [0x01] = compatibility.is_key_pressed(0x01),
        [0x02] = compatibility.is_key_pressed(0x02)
    }

    local objects = {}
    for i, object in pairs(library.directs) do
        if object.active and object.class ~= 'text' then
            local mouse_over = library.mouse_over(mouse_pos, object)
            local was_hovered = last_hovered[i]

            for _, connection in pairs(object.inputs.connections) do
                local keycode, mode, callback = connection.keycode, connection.mode, connection.callback

                if keycode == 'hover' then
                    if mouse_over and not was_hovered and mode == 'began' then
                        callback()
                    elseif not mouse_over and was_hovered and mode == 'ended' then
                        callback()
                    end
                else
                    local is_pressed = pressed[keycode]
                    if mouse_over then
                        object.mouse_over = true
                        if is_pressed then
                            if mode == 'began' and not object.inputs.active[keycode] and not last_pressed[keycode] then
                                objects[i] = {object = object, keycode = keycode, callback = callback}
                            end
                        elseif object.inputs.active[keycode] then
                            object.inputs.active[keycode] = false
                            for _, _connection in pairs(object.inputs.connections) do
                                if _connection.keycode == keycode and _connection.mode == 'ended' then
                                    _connection.callback()
                                end
                            end
                        end
                    else
                        object.mouse_over = false
                        if not is_pressed and object.inputs.active[keycode] then
                            object.inputs.active[keycode] = false
                            for _, _connection in pairs(object.inputs.connections) do
                                if _connection.keycode == keycode and _connection.mode == 'ended' then
                                    _connection.callback()
                                end
                            end
                        end
                    end
                end
            end

            last_hovered[i] = mouse_over
        end
    end

    local topmost, highest = nil, 0
    for i, object in pairs(objects) do
        if i > highest then
            topmost = object
            highest = i
        end
    end

    if topmost then
        topmost.object.inputs.active[topmost.keycode] = true
        topmost.callback()  
    end

    last_pressed = pressed
end)

compatibility.render_connection(function()
    local tick = compatibility.tick()

    for _, object in pairs(library.objects) do
        for i, tween in pairs(object.tweens) do
            local passed = (tick - tween.start) / tween.duration
            local property = tween.property

            if passed >= 1 then
                object[property] = tween.to
                object.tweens[i] = nil
            else
                if property == 'alpha' then
                    object[property] = tween.from + (tween.to - tween.from) * passed
                elseif property == 'size' or property == 'position' then
                    local from, to = tween.from, tween.to

                    object[property] = UDim2.new(
                        from.Width + (to.Width - from.Width) * passed,
                        from.X + (to.X - from.X) * passed,
                        from.Height + (to.Height - from.Height) * passed,
                        from.Y + (to.Y - from.Y) * passed
                    )
                elseif property == 'color' or property == 'start' or property == 'finish' then
                    local from, to = tween.from, tween.to

                    local fr, fg, fb = from.R, from.G, from.B
                    local tr, tg, tb = to.R, to.G, to.B

                    if compatibility.context == 'RbxCli' then
                        fr = fr / 255
                        fg = fg / 255
                        fb = fb / 255

                        tr = tr / 255
                        tg = tg / 255
                        tb = tb / 255
                    end

                    object[property] = Color3.new(
                        fr + (tr - fr) * passed,
                        fg + (tg - fg) * passed,
                        fb + (tb - fb) * passed
                    )
                end
            end
        end
    end
end)

compatibility.render_connection(function()
    local menu_state = compatibility.get_menu_state()

    for _, object in pairs(library.directs) do
        local valid = true
        if not menu_state and not object.always then valid = false end

        if valid and object.active then
            if object.class == 'frame' then
                local size, position = object.absolute_size, object.absolute_position
                compatibility.draw_rect_filled(position.X, position.Y, size.X, size.Y, object.color, object.rounding or 0, object.alpha)
            elseif object.class == 'text' then
                local position = object.absolute_position
                compatibility.draw_text(object.text, position.X, position.Y - (compatibility.context == 'RbxCli' and 4 or 0), object.color, library.font, object.alpha)
            elseif object.class == 'gradient' then
                local size, position = object.absolute_size, object.absolute_position
                compatibility.draw_gradient(position.X, position.Y, size.X, size.Y, object.start, object.finish, object.horizontal, object.start_alpha or object.alpha, object.finish_alpha or object.alpha)
            elseif object.class == 'image' then
                local size, position = object.absolute_size, object.absolute_position
                compatibility.draw_image(object.texture, position.X, position.Y, size.X, size.Y, object.color, object.alpha)
            end
        end
    end
end)

library.UDim2 = UDim2
library.Vector2 = Vector2
return library
end)
