local database = {}
local identify = function(model)
    local indentifiers = {}
    for _, child in pairs(compatibility.get_children(model)) do
        local sclass = child.ClassName
        if sclass == 'MeshPart' then
            indentifiers[#indentifiers+1] = memory.read(child.Address, 'MeshPart', 'MeshId')
        elseif sclass == 'UnionOperation' then
            indentifiers[#indentifiers+1] = memory.read(child.Address, 'MeshPart', 'MeshSize')
        end
    end

    local matches = {}
    for _, entry in pairs(database) do
        local count = 0
        for _, indentifier in pairs(entry.indentifiers) do
            for _, comp_val in pairs(indentifiers) do
                if type(comp_val) == 'string' then
                    if comp_val == indentifier.mesh_id then
                        count = count + 1
                        break
                    end
                elseif indentifier.mesh_size:FuzzyEq(comp_val) then
                    count = count + 1
                    break
                end
            end
        end

        if count ~= 0 then
            matches[#matches+1] = {
                name = entry.name,
                class = entry.class,
                count = count
            }
        end
    end

    local closest, last = nil, 0
    for _, match in pairs(matches) do
        if match.count > last then
            last = match.count
            closest = match
        end
    end

    return closest
end

local get_weapon_parts = function(weapon)
    local sight, barrel, trigger = nil, nil, nil

    local sizes = {
        Vector3.new(0.16, 0.16, 0.16),
        Vector3.new(0.2, 0.2, 0.2),
        Vector3.new(0.24, 0.24, 0.24),
        Vector3.new(0.16, 0.16, 0.05),
        Vector3.new(0.05, 0.05, 0.05),
        Vector3.new(0.2, 0.2, 0.24)
    }

    local exclusions = {
        ['rbxassetid://88120778773305'] = true,
        ['rbxassetid://77266865550782'] = true,
        ['rbxassetid://116280188206357'] = true,
        ['rbxassetid://96806825447298'] = true,
        ['rbxassetid://112618561373943'] = true,
        ['rbxassetid://135721383007775'] = true,
        ['rbxassetid://99260639965605'] = true,
        ['rbxassetid://101821289727532'] = true,
        ['rbxassetid://95081208379386'] = true,
        ['rbxassetid://75543113759167'] = true,
        ['rbxassetid://82770959000270'] = true,
        ['rbxassetid://135353464699156'] = true,
        ['rbxassetid://134505869653420'] = true,
        ['rbxassetid://135660342065125'] = true,
        ['rbxassetid://106311478569306'] = true,
        ['rbxassetid://94124245733772'] = true,
        ['rbxassetid://90393139982241'] = true,
        ['rbxassetid://119822236949970'] = true,
        ['rbxassetid://109343623965619'] = true,
        ['rbxassetid://124803770142862'] = true
    }

    for _, child in pairs(compatibility.get_children(weapon)) do
        local possible = true

        local class = child.ClassName
        if not class == 'Part' or not class == 'MeshPart' then
            possible = false
        end

        local special_mesh = compatibility.find_first_child_of_class(child, 'SpecialMesh')
        if not special_mesh and compatibility.find_first_child(child, 'Sound') then
            possible = false
        end

        if compatibility.find_first_child_of_class(child, 'IntValue') then
            possible = false
        end

        if class == 'MeshPart' and exclusions[memory.read(child.Address, 'MeshPart', 'MeshId')] then
            possible = false
        end

        if possible then
            if not sight and compatibility.find_first_child_of_class(child, 'SurfaceGui') and not compatibility.find_first_child_of_class(child, 'BillboardGui') then
                sight = child
            end

            local size = child.Size
            for _, comp in pairs(sizes) do
                if size:FuzzyEq(comp, 0.02) then
                    local weld = compatibility.find_first_child_of_class(child, 'Weld')

                    if weld then
                        if compatibility.find_first_child_of_class(child, 'Motor6D') then trigger = child end
                    else
                        if special_mesh then
                            if not sight then
                                local mesh = memory.read(special_mesh.Address, 'SpecialMesh', 'MeshId')
                                if string.find(mesh, '12272787618') then
                                    if not barrel then barrel = child end
                                else
                                    sight = child
                                end
                            else
                                if not barrel then barrel = child end
                            end
                        elseif not weld then
                            if sight then barrel = child else sight = child end
                        end
                    end
                end
            end
        end
    end

    return sight, barrel, trigger
end

local set_arms = function(color, transparency, reflectance, material)
    local left_arm, right_arm = cache.instances.left_arm, cache.instances.right_arm
    if not left_arm or not right_arm then return end

    for _, descendant in pairs(compatibility.get_children(left_arm)) do
        local sclass = descendant.ClassName
        if sclass == 'MeshPart' or sclass == 'Part' then
            local address = descendant.Address

            local primitive = memory.read(address, 'BasePart', 'Primitive')
            memory.write(primitive, 'BasePart', 'Material', material)

            local new_color = color
            if compatibility.context ~= 'RbxCli' then
                new_color = {R = color.R * 255, G = color.G * 255, B = color.B * 255}
            end
            memory.write(address, 'BasePart', 'Color', new_color)

            memory.write(address, 'BasePart', 'Transparency', transparency)
            memory.write(address, 'BasePart', 'Reflectance', reflectance)
        end
    end

    for _, descendant in pairs(compatibility.get_children(right_arm)) do
        local sclass = descendant.ClassName
        if sclass == 'MeshPart' or sclass == 'Part' then
            local address = descendant.Address

            local primitive = memory.read(address, 'BasePart', 'Primitive')
            memory.write(primitive, 'BasePart', 'Material', material)

            local new_color = color
            if compatibility.context ~= 'RbxCli' then
                new_color = {R = color.R * 255, G = color.G * 255, B = color.B * 255}
            end
            memory.write(address, 'BasePart', 'Color', new_color)

            memory.write(address, 'BasePart', 'Transparency', transparency)
            memory.write(address, 'BasePart', 'Reflectance', reflectance)
        end
    end
end

local buffer, buffer_read, buffer_write, buffer_readf32, buffer_writef32, successful = buffer, mem_api.read, mem_api.write, buffer and buffer.readf32, buffer and buffer.writef32, Enum and Enum.ProcessReadResult and Enum.ProcessReadResult.Successful
local offset_motor = function(primitive, x, y, z)
    if buffer then
        local s0, c0 = buffer_read(primitive + memory.offsets.Motor6D.C0[1], 48)
        local s1, c1 = buffer_read(primitive + memory.offsets.Motor6D.C1[1], 48)

        if s0 == successful and s1 == successful then
            buffer_writef32(c1, 36, x * buffer_readf32(c0, 0) + y * buffer_readf32(c0, 12) + z * buffer_readf32(c0, 24))
            buffer_writef32(c1, 40, x * buffer_readf32(c0, 4) + y * buffer_readf32(c0, 16) + z * buffer_readf32(c0, 28))
            buffer_writef32(c1, 44, x * buffer_readf32(c0, 8) + y * buffer_readf32(c0, 20) + z * buffer_readf32(c0, 32))

            buffer_write(primitive + memory.offsets.Motor6D.C1[1], c1)
        end
    else
        local c0 = memory.get_components(primitive, memory.offsets.Motor6D.C0[1])
        local c1 = memory.get_components(primitive, memory.offsets.Motor6D.C1[1])

        c1[10] = x * c0[1] + y * c0[4] + z * c0[7]
        c1[11] = x * c0[2] + y * c0[5] + z * c0[8]
        c1[12] = x * c0[3] + y * c0[6] + z * c0[9]

        memory.write_components(primitive, memory.offsets.Motor6D.C1[1], c1)
    end
end

local v3_new = Vector3.new
local lerp_v3 = function(a, b, c)
    local ax, ay, az = a.X, a.Y, a.Z
    return v3_new(
        ax + (b.X - ax) * c,
        ay + (b.Y - ay) * c,
        az + (b.Z - az) * c
    )
end

