cache.instances = {}; do
    local function search_instance(instance, path)
        if not instance then return nil end

        local current = instance

        for _, name in pairs(path) do
            current = compatibility.find_first_child(current, name)
            if not current then
                return nil
            end
        end

        return current
    end

    local last_datamodel = nil
    compatibility.update_connection(function()
        if not memory.offsets then return end

        local datamodel = compatibility.get_datamodel()
        if datamodel and last_datamodel and datamodel.Address ~= last_datamodel.Address then
            last_datamodel = nil
            for i, tbl in pairs(cache) do
                if type(tbl) == 'table' then
                    cache[i] = {}
                end
            end
            cache.local_team = 'Unknown'
        end

        if not last_datamodel then
            if datamodel then
                local local_player = compatibility.get_local_player()
                local local_player_name = local_player and local_player.Name

                local players = compatibility.find_first_child_of_class(datamodel, 'Players')
                local workspace = compatibility.find_first_child_of_class(datamodel, 'Workspace')
                local replicated_storage = compatibility.find_first_child_of_class(datamodel, 'ReplicatedStorage')

                local image_rear_layer = search_instance(local_player, {'PlayerGui', 'UnscaledScreenGui', 'DisplayScope', 'ImageRearLayer'})
                local image_front_layer = search_instance(local_player, {'PlayerGui', 'UnscaledScreenGui', 'DisplayScope', 'ImageFrontLayer'})

                local text_mag_count = search_instance(local_player, {'PlayerGui', 'HudScreenGui', 'Main', 'DisplayStatus', 'TextMagCount'})
                local text_firemode = search_instance(local_player, {'PlayerGui', 'HudScreenGui', 'Main', 'DisplayStatus', 'TextFiremode'})

                local ghosts_leaderboard = search_instance(local_player, {'PlayerGui', 'LeaderboardScreenGui', 'DisplayScoreFrame', 'Container', 'DisplayGhostBoard', 'Container'})
                local phantoms_leaderboard = search_instance(local_player, {'PlayerGui', 'LeaderboardScreenGui', 'DisplayScoreFrame', 'Container', 'DisplayPhantomBoard', 'Container'})

                local weapon_database = search_instance(replicated_storage, {'Content', 'ProductionContent', 'WeaponDatabase'})
                local attachment_database = search_instance(replicated_storage, {'Content', 'ProductionContent', 'AttachmentDatabase'})

                local left_arm = search_instance(replicated_storage, {'Character', 'Left Arm'})
                local right_arm = search_instance(replicated_storage, {'Character', 'Right Arm'})

                local ghosts = search_instance(replicated_storage, {'Character', 'Bodies', 'Ghosts'})
                local phantoms = search_instance(replicated_storage, {'Character', 'Bodies', 'Phantoms'})

                local camera = workspace and compatibility.find_first_child(workspace, 'Camera')
                local terrain = workspace and compatibility.find_first_child(workspace, 'Terrain')

                local ignore = workspace and compatibility.find_first_child(workspace, 'Ignore')
                    local misc = ignore and compatibility.find_first_child(ignore, 'Misc')
                    local gun_drop = ignore and compatibility.find_first_child(ignore, 'GunDrop')

                local pfolders = workspace and compatibility.find_first_child(workspace, 'Players')

                local loadout_container = search_instance(local_player, {'PlayerGui', 'MenuScreenGui', 'Pages', 'PageMainMenu', 'DisplayLoadoutClass', 'Container'})

                if local_player_name and players and camera and terrain and gun_drop and pfolders and weapon_database and attachment_database and left_arm and right_arm and ghosts and phantoms and misc and image_rear_layer and image_front_layer and text_mag_count and text_firemode and ghosts_leaderboard and phantoms_leaderboard and loadout_container then
                    last_datamodel = datamodel

                    cache.instances.players = players

                    cache.instances.local_player = local_player
                    cache.instances.local_player_name = local_player_name

                    cache.instances.camera = camera
                    cache.instances.terrain = terrain
                    cache.instances.ignore = ignore
                    cache.instances.gun_drop = gun_drop

                    cache.instances.left_arm = left_arm
                    cache.instances.right_arm = right_arm

                    cache.instances.ghosts = ghosts
                    cache.instances.phantoms = phantoms

                    cache.instances.image_rear_layer = image_rear_layer
                    cache.instances.image_front_layer = image_front_layer

                    cache.instances.misc = misc

                    cache.instances.text_mag_count = text_mag_count
                    cache.instances.text_firemode = text_firemode

                    cache.instances.ghosts_leaderboard = ghosts_leaderboard
                    cache.instances.phantoms_leaderboard = phantoms_leaderboard

                    if compatibility.find_first_child_of_class(pfolders, 'Folder') then
                        cache.instances.pfplayers = compatibility.get_children(pfolders)
                    else
                        cache.instances.pfplayers = pfolders
                    end

                    database = {}
                    local weapon_models = {}
                    for _, class in pairs(compatibility.get_children(weapon_database)) do
                        local csname = class.Name

                        for _, sub in pairs(compatibility.get_children(class)) do
                            -- if not pf_dump[sub.Name] and not string.find(csname, 'HAND') and not string.find(csname, 'FRAGMENTATION') and not string.find(csname, 'HIGH EXPLOSIVE') and not string.find(csname, 'IMPACT') then
                            --     print(sub.Name)
                            -- end

                            for _, model in pairs(compatibility.get_children(sub)) do
                                if string.find(model.Name, 'Main') then
                                    weapon_models[model.Name] = model

                                    local indentifiers = {}
                                    for _, child in pairs(compatibility.get_children(model)) do
                                        local sclass = child.ClassName
                                        if sclass == 'MeshPart' then
                                            indentifiers[#indentifiers + 1] = {
                                                class = sclass,
                                                mesh_id = memory.read(child.Address, 'MeshPart', 'MeshId'),
                                                mesh_size = memory.read(child.Address, 'MeshPart', 'MeshSize')
                                            }
                                        elseif sclass == 'UnionOperation' then
                                            indentifiers[#indentifiers + 1] = {
                                                class = sclass,
                                                mesh_size = memory.read(child.Address, 'MeshPart', 'MeshSize')
                                            }
                                        end
                                    end

                                    database[#database + 1] = {
                                        name = sub.Name,
                                        class = csname,
                                        indentifiers = indentifiers
                                    }

                                    break
                                end
                            end
                        end
                    end
                    cache.instances.weapon_models = weapon_models
                    cache.instances.weapon_database = weapon_database

                    local attachment_models = {}
                    for _, model in pairs(compatibility.get_descendants(attachment_database)) do
                        if model:IsA('Model') then
                            weapon_models[model.Name] = model
                        end
                    end
                    cache.instances.attachment_models = attachment_models

                    cache.instances.loadout_container = loadout_container
                end
            end
        end
    end)
end

cache.local_player = {}; do
    compatibility.update_connection(function()
        if not memory.offsets then return end

        local camera = cache.instances.camera
        if not camera then return end

        local weapon, left_arm, right_arm = nil, nil, nil
        for _, child in pairs(compatibility.get_children(camera)) do
            if child:IsA('Model') then
                if compatibility.find_first_child(child, 'Sleeves') then
                    if compatibility.find_first_child(child, 'Watch') then
                        left_arm = child
                    else
                        right_arm = child
                    end
                else
                    weapon = child
                end
            end
        end

        if weapon then
            local address = weapon.Address

            local cweapon = cache.local_player.weapon
            if cweapon and cweapon ~= address then
                cache.local_player.weapon = nil
            end

            if not cache.local_player.weapon then
                cache.local_player.weapon = address
                cache.local_player.weapon_max_ammo = 0

                local remove_textures = false
                for _, v in pairs(flags['vm_removals']) do
                    if v == 'Weapon Textures' then
                        remove_textures = true
                        break
                    end
                end

                local skin, skin_color, skin_transparency, skin_offset_x, skin_offset_y, skin_scale_x, skin_scale_y = pf_skins[flags['weapon_skin_texture']], flags['weapon_skin_color'].color, 1 - (flags['weapon_skin_color'].alpha / 255), flags['weapon_skin_offset_x'], flags['weapon_skin_offset_y'], flags['weapon_skin_scale_x'], flags['weapon_skin_scale_y']
                local color, transparency, reflectance, material = flags['vm_weapon_color'].color, 1 - (flags['vm_weapon_color'].alpha / 255), flags['vm_weapon_reflectance'], materials[flags['vm_weapon_material']]
                if flags['vm_weapon'] or flags['weapon_skin'] or remove_textures then
                    for _, child in pairs(compatibility.get_descendants(weapon)) do
                        local sclass = child.ClassName
                        local address = child.Address
                        if sclass == 'Texture' then
                            if remove_textures then
                                memory.write(address, 'Texture', 'Transparency', 1)
                                memory.write(address, 'Texture', 'LocalTransparencyModifier', 1)
                            elseif flags['weapon_skin'] then
                                memory.write(address, 'Texture', 'Color3', skin_color)
                                memory.write(address, 'Texture', 'ColorMapContent', skin)
                                memory.write(address, 'Texture', 'Transparency', skin_transparency)
                                memory.write(address, 'Texture', 'OffsetStudsU', skin_offset_x)
                                memory.write(address, 'Texture', 'OffsetStudsV', skin_offset_y)
                                memory.write(address, 'Texture', 'StudsPerTileU', skin_scale_x)
                                memory.write(address, 'Texture', 'StudsPerTileV', skin_scale_y)
                            end
                        elseif sclass == 'Decal' then
                            if remove_textures then
                                memory.write(address, 'Decal', 'ColorMapContent', 'rbxassetid://0')
                            end
                        elseif sclass == 'MeshPart' or sclass == 'Part' then
                            if flags['vm_weapon'] and child.Transparency < 0.9 then
                                local primitive = memory.read(address, 'BasePart', 'Primitive')
                                memory.write(primitive, 'BasePart', 'Material', material)

                                local new_color = color
                                if compatibility.context ~= 'RbxCli' then
                                    new_color = {R = color.R * 255, G = color.G * 255, B = color.B * 255}
                                end
                                memory.write(address, 'BasePart', 'Color', new_color)

                                memory.write(address, 'BasePart', 'Transparency', transparency)
                                memory.write(address, 'BasePart', 'Reflectance', reflectance)
                            end
                        elseif sclass == 'UnionOperation' then
                            if flags['vm_weapon'] and child.Transparency < 0.9 then
                                local new_color = color
                                if compatibility.context ~= 'RbxCli' then
                                    new_color = {R = color.R * 255, G = color.G * 255, B = color.B * 255}
                                end
                                memory.write(address, 'BasePart', 'Color', new_color)

                                memory.write(address, 'BasePart', 'Transparency', transparency)
                                memory.write(address, 'BasePart', 'Reflectance', reflectance)

                                local primitive = memory.read(address, 'BasePart', 'Primitive')
                                memory.write(primitive, 'BasePart', 'Material', material)

                                memory.write(address, 'PartOperation', 'UsePartColor', 1)
                            end
                        end
                    end
                end

                local indentity = identify(weapon)
                if indentity then
                    local gun_data = pf_dump[indentity.name]
                    if gun_data then
                        cache.local_player.weapon_name = gun_data.display_name or indentity.name
                        cache.local_player.weapon_speed = gun_data.bulletspeed
                    end
                else
                    cache.local_player.weapon_name = nil
                    cache.local_player.weapon_speed = 3000
                end

                local sight, barrel, trigger = get_weapon_parts(weapon)
                cache.local_player.weapon_sight = sight
                cache.local_player.weapon_barrel = barrel
                cache.local_player.weapon_trigger = trigger

                if trigger then
                    local motor = compatibility.find_first_child_of_class(trigger, 'Motor6D')
                    if motor then
                        cache.local_player.weapon_motor = motor
                    end
                end

                if left_arm and right_arm then
                    local larm = compatibility.find_first_child_of_class(left_arm, 'Part')
                    local left_motor = larm and compatibility.find_first_child_of_class(larm, 'Motor6D')
                    cache.local_player.left_motor = left_motor

                    local rarm = compatibility.find_first_child_of_class(right_arm, 'Part')
                    local right_motor = rarm and compatibility.find_first_child_of_class(rarm, 'Motor6D')
                    cache.local_player.right_motor = right_motor
                end
            end

            local text_mag_count, text_firemode = cache.instances.text_mag_count, cache.instances.text_firemode
            if text_mag_count and text_firemode then
                if not cache.local_player.weapon_max_ammo then
                    cache.local_player.weapon_max_ammo = 0
                end

                local current = tonumber(compatibility.context == 'Serotonin' and text_mag_count.Value or text_mag_count.Text)
                if current and current > cache.local_player.weapon_max_ammo then
                    cache.local_player.weapon_max_ammo = current
                end

                cache.local_player.weapon_ammo = current
            end
        else
            cache.local_player.weapon_name = nil
            cache.local_player.weapon_ammo = 0
            cache.local_player.weapon_max_ammo = 0
            cache.local_player.weapon_motor = nil
            cache.local_player.left_motor = nil
            cache.local_player.right_motor = nil
            cache.local_player.weapon = nil
            cache.local_player.weapon_sight = nil
            cache.local_player.weapon_barrel = nil
            cache.local_player.weapon_trigger = nil
        end
    end)
end

cache.misc = {}; do
    compatibility.update_connection(function()
        if not memory.offsets then return end
        if not cache.instances.misc then return end
        if not flags['tracers'] then return end

        local indexed = {}

        local barrel = cache.local_player.weapon_barrel
        if barrel then
            for _, child in pairs(compatibility.get_children(barrel)) do
                local address = child.Address
                indexed[address] = true

                if not cache.misc[address] then
                    if child:IsA('Sound') then
                        cache.last_fire_tick = compatibility.tick()
                        cache.last_fire_direction = cache.local_player.weapon_sight and memory.get_cframe(cache.local_player.weapon_sight).LookVector or Vector3.new(0, 0, 0)
                        cache.misc[address] = true
                        return
                    end
                end
            end
        end

        for _, child in pairs(compatibility.get_children(cache.instances.misc)) do
            local address = child.Address
            indexed[address] = true

            if not cache.misc[address] then
                if child.Name == 'MuzzleFlash' then
                    local flash = compatibility.find_first_child(child, 'Flash')
                    if flash then
                        if (flash.Position - (barrel and barrel.Position or cache.local_position)).Magnitude < 10 then
                            cache.last_fire_tick = compatibility.tick()
                            cache.last_fire_direction = cache.local_player.weapon_sight and memory.get_cframe(cache.local_player.weapon_sight).LookVector or Vector3.new(0, 0, 0)
                            cache.misc[address] = true
                            return
                        end
                    end
                else
                    cache.misc[address] = 'nil'
                end
            end
        end

        for i in pairs(cache.misc) do
            if not indexed[i] then
                cache.misc[i] = nil
            end
        end
    end)
end

cache.tracers = {}; do
    compatibility.update_connection(function()
        if not cache.instances.terrain then return end
        if not flags['tracers'] then return end

        local tick = compatibility.tick()

        local indexed = {}

        for _, child in pairs(compatibility.get_children(cache.instances.terrain)) do
            local address = child.Address
            indexed[address] = true

            if not cache.tracers[address] then
                if child:IsA('Beam') then
                    local attachment0 = memory.read(address, 'Beam', 'Attachment0')
                    local attachment1 = memory.read(address, 'Beam', 'Attachment1')

                    if attachment0 ~= 0 and attachment1 ~= 0 then
                        local pos0, pos1 = memory.read(attachment0, 'Attachment', 'TransformPosition'), memory.read(attachment1, 'Attachment', 'TransformPosition')

                        if tick - cache.last_fire_tick < 15 then
                            local color_sequence = memory.get_color_sequence(address, memory.offsets.Beam.ColorArray[1])
                            for _, v in pairs(color_sequence) do
                                if v.time == 0 then
                                    v.color = flags['tracers_color1'].color
                                else
                                    v.color = flags['tracers_color2'].color
                                end
                            end
                            memory.write_color_sequence(address, memory.offsets.Beam.ColorArray[1], color_sequence)

                            memory.write(address, 'Beam', 'TextureLength', 10)
                            memory.write(address, 'Beam', 'TextureMode', 1)
                            memory.write(address, 'Beam', 'Texture', textures[flags['tracers_texture']][1])
                            memory.write(address, 'Beam', 'Segments', 1)

                            local start_pos = cache.local_player.weapon_barrel and cache.local_player.weapon_barrel.Position or pos0
                            local direction = cache.last_fire_direction

                            local target = compatibility.get_entity_target()
                            if target then
                                direction = (target.Position - start_pos).Unit
                            end

                            cache.tracers[address] = {
                                beam = child.Address,
                                start_pos = start_pos,
                                direction = direction,
                                attachment0 = attachment0,
                                attachment1 = attachment1
                            }
                        else
                            cache.tracers[address] = 'nil'
                        end
                    end
                else
                    cache.tracers[address] = 'nil'
                end
            end
        end

        for i in pairs(cache.tracers) do
            if not indexed[i] then
                cache.tracers[i] = nil
            end
        end
    end)
end

cache.grenades = {}; do
    compatibility.update_connection(function()
        local misc = cache.instances.misc
        if not misc then return end

        local indexed = {}

        local tick = compatibility.tick()

        for _, child in pairs(compatibility.get_children(misc)) do
            local address = child.Address
            indexed[address] = true

            if not cache.grenades[address] then
                if child.Name == 'Trigger' and child:IsA('MeshPart') then
                    local gdata = pf_dump[memory.read(child.Address, 'MeshPart', 'MeshId')]
                    if gdata then
                        cache.grenades[address] = {
                            name = gdata.display_name,
                            path = {child.Position},
                            start = tick,
                            root_part = child,
                            position = child.Position,
                            fusetime = gdata.fusetime * 1000,
                            blastradius = gdata.blastradius,
                            range0 = gdata.range0,
                            range1 = gdata.range1,
                            damage0 = gdata.damage0,
                            damage1 = gdata.damage1,
                            head_multiplier = gdata.head_multiplier,
                            torso_multiplier = gdata.torso_multiplier,
                            impact = gdata.impact
                        }
                    else
                        cache.grenades[address] = 'nil'
                    end
                else
                    cache.grenades[address] = 'nil'
                end
            end
        end

        for i, v in pairs(cache.grenades) do
            if indexed[i] then
                if v ~= 'nil' then
                    if tick - v.start > v.fusetime then
                        cache.grenades[i] = 'nil'
                    else
                        local new_pos = v.root_part.Position
                        if (new_pos - v.path[#v.path]).Magnitude > 3 then
                            v.path[#v.path+1] = new_pos
                        end

                        v.distance = (new_pos - cache.local_position).Magnitude
                        v.position = lerp_v3(v.position, new_pos, 0.6)
                    end
                end
            else
                cache.grenades[i] = nil
            end
        end
    end)
end

cache.players = {}; do
    compatibility.update_connection(function()
        if not memory.offsets then return end

        local players = cache.instances.pfplayers
        if not players then return end

        local indexed = {}

        if type(players) == 'table' then
            for _, folder in pairs(players) do
                for _, child in pairs(compatibility.get_children(folder)) do
                    local address = child.Address
                    indexed[address] = true

                    if not cache.players[address] then
                        local data = {parts = {}, step_points = {}}

                        local cosmetics = compatibility.find_first_child_of_class(child, 'Folder')
                        if cosmetics then
                            for _, cosmetic in pairs(compatibility.get_children(cosmetics)) do
                                if cosmetic:IsA('MeshPart') then
                                    local asset = memory.read(cosmetic.Address, 'MeshPart', 'MeshId')
                                    if asset == 'rbxassetid://100979280359642' then
                                        data.left_foot = cosmetic
                                    elseif asset == 'rbxassetid://125659201096115' then
                                        data.right_foot = cosmetic
                                    end
                                end
                            end
                        end

                        for _, part in pairs(compatibility.get_children(child)) do
                            local name_tag = compatibility.find_first_child(part, 'NameTagGui')
                            if name_tag then
                                local player_tag = compatibility.find_first_child(name_tag, 'PlayerTag')
                                if player_tag then
                                    data.head = part
                                    data.name = compatibility.context == 'Serotonin' and player_tag.Value or player_tag.Text

                                    local team_color = player_tag.TextColor3
                                    data.enemy = team_color and team_color.R ~= 0 or false
                                end
                            else
                                local spot_light = compatibility.find_first_child_of_class(part, 'SpotLight')
                                if spot_light then
                                    data.torso = part
                                    data.velocity = Vector3.new(0, 0, 0)
                                    data.position = part.Position
                                    data.predicted = Vector3.new(0, 0, 0)
                                    data.step_position = part.Position
                                elseif part:IsA('Part') or part:IsA('MeshPart') then
                                    data.parts[#data.parts+1] = part
                                end
                            end
                        end

                        if data.head and data.torso then
                            if data.enemy then
                                cache.players[address] = data
                            else
                                cache.players[address] = 'nil'
                            end
                        end
                    end
                end
            end
        else
            for _, child in pairs(compatibility.get_children(players)) do
                local address = child.Address
                indexed[address] = true

                if not cache.players[address] then
                    local head, torso, cosmetics = compatibility.find_first_child(child, 'Head'), compatibility.find_first_child(child, 'Torso'), compatibility.find_first_child_of_class(child, 'Folder')
                    if head and torso and cosmetics then
                        local parts = {
                            compatibility.find_first_child(child, 'Left Arm'),
                            compatibility.find_first_child(child, 'Right Arm'),
                            compatibility.find_first_child(child, 'Left Leg'),
                            compatibility.find_first_child(child, 'Right Leg')
                        }

                        local left_foot, right_foot = nil, nil
                        for _, cosmetic in pairs(compatibility.get_children(cosmetics)) do
                            if cosmetic:IsA('MeshPart') then
                                local asset = memory.read(cosmetic.Address, 'MeshPart', 'MeshId')
                                if asset == 'rbxassetid://11232478025' then
                                    left_foot = cosmetic
                                elseif asset == 'rbxassetid://11232477996' then
                                    right_foot = cosmetic
                                end
                            end
                        end

                        entity.add_model(address, {
                            Name = tostring(address),
                            Character = child,
                            PrimaryPart = torso,
                            Humanoid = compatibility.find_first_child_of_class(child, 'Humanoid')
                        })

                        cache.players[address] = {
                            model = true,
                            name = tostring(address),
                            head = head,
                            torso = torso,
                            position = torso.Position,
                            predicted = Vector3.new(0, 0, 0),
                            parts = parts,
                            left_foot = left_foot,
                            right_foot = right_foot,
                            step_points = {},
                            step_position = torso.Position,
                        }
                    end
                end
            end
        end

        for i, entry in pairs(cache.players) do
            if indexed[i] then
                if entry ~= 'nil' then
                    local old_pos = entry.position
                    local new_pos = entry.torso.Position
                    local velocity = (new_pos - old_pos) / 0.01

                    if flags['players_steps'] then
                        local step_pos = entry.step_position
                        local diff = (Vector3.new(new_pos.X, 0, new_pos.Z) - Vector3.new(step_pos.X, 0, step_pos.Z)).Magnitude
                        if diff > 1.5 then
                            local foot, name = entry.left_foot, 'left'
                            local steps = #entry.step_points

                            if steps ~= 0 then
                                local last = entry.step_points[steps]
                                if last and last.foot == 'left' then
                                    foot = entry.right_foot
                                    name = 'right'
                                end
                            end

                            if foot then
                                local cframe = memory.get_cframe(foot)
                                if cframe then
                                    cframe.Position = cframe.Position - Vector3.new(0, foot.Size.Y / 2, 0)
                                    local corners = cframe and memory.get_half_corners(cframe, Vector3.new(1, 0.1, 1))

                                    entry.step_points[steps+1] = {
                                        foot = name,
                                        start = compatibility.tick(),
                                        corners = corners
                                    }
                                end

                                entry.step_position = new_pos
                            end
                        end
                    end

                    entry.position = new_pos
                    entry.velocity = velocity
                end
            else
                if entry ~= 'nil' and entry.model then
                    entity.remove_model(i)
                end
                cache.players[i] = nil
            end
        end
    end)
end

cache.hits = {}; do
    compatibility.update_connection(function()
        if not memory.offsets then return end

        local ignore = cache.instances.ignore
        if not ignore then return end

        if not flags['players_hit_chams'] and not flags['players_hit_marker'] then return end

        local indexed = {}

        for _, child in pairs(compatibility.get_children(ignore)) do
            local address = child.Address
            indexed[address] = true

            if not cache.hits[address] then
                if child.Name == 'DamagePart' and compatibility.find_first_child(child, 'BillboardDamage') then
                    local position = child.Position

                    local closest, distance = nil, 10
                    for _, entry in pairs(cache.players) do
                        if entry ~= 'nil' then
                            local new = (position - entry.position).Magnitude
                            if new < distance then
                                closest = entry
                                distance = new
                            end
                        end
                    end

                    if closest then
                        local corners = {}

                        local head_cf = memory.get_cframe(closest.head)
                        if head_cf then
                            corners[#corners+1] = memory.get_corners(memory.get_cframe(closest.head), Vector3.new(1, 1, 1))
                        end

                        local torso_cf = memory.get_cframe(closest.torso)
                        if torso_cf then
                            corners[#corners+1] = memory.get_corners(memory.get_cframe(closest.torso), Vector3.new(2, 2, 1))
                        end

                        for _, limb in pairs(closest.parts) do
                            local cf = memory.get_cframe(limb)
                            if cf then
                                corners[#corners+1] = memory.get_corners(cf, Vector3.new(1, 2, 1))
                            end
                        end

                        cache.hits[address] = {
                            position = child.Position,
                            start = compatibility.tick(),
                            target = closest,
                            corners = corners
                        }
                    end
                else
                    cache.hits[address] = 'nil'
                end
            end
        end

        for i in pairs(cache.hits) do
            if not indexed[i] then
                cache.hits[i] = nil
            end
        end
    end)
end

cache.leaderboard = {}; do
    compatibility.slow_connection(function()
        if not memory.offsets then return end
        if not cache.instances.ignore then return end
        if compatibility.find_first_child_of_class(cache.instances.ignore, 'Model') then return end

        cache.leaderboard = {}

        local local_player_name = cache.instances.local_player_name

        for _, entry in pairs(compatibility.get_children(cache.instances.ghosts_leaderboard)) do
            if entry:IsA('Frame') then
                local kdr = compatibility.find_first_child(entry, 'TextKdr')
                local rank = compatibility.find_first_child(entry, 'TextRank')
                local name = compatibility.find_first_child(entry, 'TextPlayer')

                if kdr and rank and name then
                    local kdr_value = compatibility.context == 'Serotonin' and kdr.Value or kdr.Text or 0
                    local rank_value = compatibility.context == 'Serotonin' and rank.Value or rank.Text or 0
                    local name_value = compatibility.context == 'Serotonin' and name.Value or name.Text or 'Nil'

                    if name_value == local_player_name then
                        cache.local_team = 'Ghosts'
                    end

                    cache.leaderboard[name_value] = {
                        kdr = kdr_value,
                        rank = rank_value,
                        name = name_value,
                        team = 'Ghosts'
                    }
                end
            end
        end

        for _, entry in pairs(compatibility.get_children(cache.instances.phantoms_leaderboard)) do
            if entry:IsA('Frame') then
                local kdr = compatibility.find_first_child(entry, 'TextKdr')
                local rank = compatibility.find_first_child(entry, 'TextRank')
                local name = compatibility.find_first_child(entry, 'TextPlayer')

                if kdr and rank and name then
                    local kdr_value = compatibility.context == 'Serotonin' and kdr.Value or kdr.Text or 0
                    local rank_value = compatibility.context == 'Serotonin' and rank.Value or rank.Text or 0
                    local name_value = compatibility.context == 'Serotonin' and name.Value or name.Text or 'Nil'

                    if name_value == local_player_name then
                        cache.local_team = 'Phantoms'
                    end

                    cache.leaderboard[name_value] = {
                        kdr = kdr_value,
                        rank = rank_value,
                        name = name_value,
                        team = 'Phantoms'
                    }
                end
            end
        end
    end)
end

