        for _, child in pairs(compatibility.get_children(cache.instances.image_rear_layer)) do
            if child:IsA('Frame') then
                memory.write(child.Address, 'GuiObject', 'Visible', 0)
            end
        end
        memory.write(cache.instances.image_front_layer.Address, 'GuiObject', 'Visible', 0)
    else
        memory.write(cache.instances.image_rear_layer.Address, 'ImageLabel', 'ImageTransparency', 0)
        for _, child in pairs(compatibility.get_children(cache.instances.image_rear_layer)) do
            if child:IsA('Frame') then
                memory.write(child.Address, 'GuiObject', 'Visible', 1)
            end
        end
        memory.write(cache.instances.image_front_layer.Address, 'GuiObject', 'Visible', 1)
    end
end)

compatibility.update_connection(function()
    if not memory.offsets then return end

    cache.local_position = compatibility.get_camera_pos(cache.instances.camera)

    local target = compatibility.get_entity_target()
    if target then
        local name = target.name
        for _, entry in pairs(cache.players) do
            if entry ~= 'nil' and entry.name == name then
                local pos = entry.position

                local bullet_speed = 2500
                if cache.local_player.weapon_speed then
                    bullet_speed = cache.local_player.weapon_speed
                end

                local origin = cache.local_player.weapon_barrel and cache.local_player.weapon_barrel.Position or cache.local_position
                local travel_time = ((pos - origin).Magnitude / bullet_speed)
                local predicted = (entry.velocity * travel_time) + Vector3.new(0, 98.1 * travel_time ^ 2, 0)

                local tx, ty, tos = compatibility.world_to_screen(pos)
                local px, py, pos = compatibility.world_to_screen(pos + predicted)

                if tos and pos then
                    local sight, barrel = cache.local_player.weapon_sight, cache.local_player.weapon_barrel

                    local pj = sight and sight or barrel and barrel
                    local cf = pj and memory.get_cframe(pj)

                    local pjx, pjy = nil, nil
                    if cf then
                        local npjx, npjy, pjos = compatibility.world_to_screen(cf.Position + (cf.LookVector * 500))
                        if pjos then
                            pjx = math.floor(npjx)
                            pjy = math.floor(npjy)
                        end
                    end

                    local final_x, final_y = tx - px, ty - py
                    if pjx and pjy then
                        local mouse_pos = compatibility.get_mouse_location()

                        local bdx = mouse_pos[1] - pjx
                        local bdy = mouse_pos[2] - pjy

                        if bdx + bdy < 250 then
                            final_x = final_x - bdx
                            final_y = final_y - bdy
                        end
                    end

                    local fov = ui.get_value('Aimbot', 'Aimbot', 'Field of View') or 400

                    if final_x > fov then
                        final_x = 0
                    elseif final_x < -fov then
                        final_x = 0
                    end

                    if final_y > fov then
                        final_y = 0
                    elseif final_y < -fov then
                        final_y = 0
                    end

                    ui.set_value('Aimbot', 'Aimbot', 'Offset X', final_x)
                    ui.set_value('Aimbot', 'Aimbot', 'Offset Y', final_y)
                end

                break
            end
        end
    end

    local weapon_trigger = cache.local_player.weapon_trigger
    if weapon_trigger then
        local new_pos = weapon_trigger.Position
        local old_pos = cache.instances.trigger_pos

        if not old_pos then
            cache.instances.trigger_pos = new_pos
            old_pos = new_pos
        end

        cache.instances.trigger_pos = lerp_v3(old_pos, new_pos, flags['weapon_display_interpolation'])
    else
        cache.instances.trigger_pos = nil
    end
end)

compatibility.render_connection(function()
    if flags['tracers'] then
        local texture_width = textures[flags['tracers_texture']][2]

        for i = 1, flags['tracers_writes'] do
            for _, tracer in pairs(cache.tracers) do
                if tracer ~= 'nil' then
                local beam = tracer.beam
                    memory.write(beam, 'Beam', 'Width0', texture_width)
                    memory.write(beam, 'Beam', 'Width1', texture_width)

                    memory.write(tracer.attachment0, 'Attachment', 'TransformPosition', tracer.start_pos)
                    memory.write(tracer.attachment1, 'Attachment', 'TransformPosition', tracer.start_pos + (tracer.direction * 250))
                end
            end
        end
    end

    if flags['vm_offset'] then
        local x, y, z = flags['vm_offset_x'], flags['vm_offset_y'], flags['vm_offset_z']
        if compatibility.is_key_pressed(0x02) then
            x = 0; y = 0; z = 0
        end

        local weapon_motor, left_motor, right_motor = cache.local_player.weapon_motor, cache.local_player.left_motor, cache.local_player.right_motor
        if weapon_motor and left_motor and right_motor then
            local prim1 = memory.read(weapon_motor.Address, 'Motor6D', 'Primitive1')
            local prim2 = memory.read(prim1, 'Motor6D', 'Primitive2')
            offset_motor(prim2, x, y, z)

            local prim1 = memory.read(left_motor.Address, 'Motor6D', 'Primitive1')
            local prim2 = memory.read(prim1, 'Motor6D', 'Primitive2')
            offset_motor(prim2, x, y, z)

            local prim1 = memory.read(right_motor.Address, 'Motor6D', 'Primitive1')
            local prim2 = memory.read(prim1, 'Motor6D', 'Primitive2')
            offset_motor(prim2, x, y, z)

            cache.instances.vm_offset = true
        end
    elseif cache.instances.vm_offset then
        local weapon_motor, left_motor, right_motor = cache.local_player.weapon_motor, cache.local_player.left_motor, cache.local_player.right_motor
        if weapon_motor and left_motor and right_motor then
            local prim1 = memory.read(weapon_motor.Address, 'Motor6D', 'Primitive1')
            local prim2 = memory.read(prim1, 'Motor6D', 'Primitive2')
            offset_motor(prim2, 0, 0, 0)

            local prim1 = memory.read(left_motor.Address, 'Motor6D', 'Primitive1')
            local prim2 = memory.read(prim1, 'Motor6D', 'Primitive2')
            offset_motor(prim2, 0, 0, 0)

            local prim1 = memory.read(right_motor.Address, 'Motor6D', 'Primitive1')
            local prim2 = memory.read(prim1, 'Motor6D', 'Primitive2')
            offset_motor(prim2, 0, 0, 0)
        end

        cache.instances.vm_offset = false
    end
end)

cache.library = library
return cache
end)
return __bundle_require("__root")